INSERT INTO spectrum_allocations(freq_start_hz, freq_end_hz, frequency_range, unit, region1, region2, region3, australian_table_of_allocations, common, footnote_ref) VALUES(3000000000000, 420000000000000, '3000–420000', 'GHZ', 'COMMON', 'COMMON', 'COMMON', '(Not allocated)', '3000 – 420 000', '');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS1A', 'In the band 1 260–1 300 MHz it is intended to accommodate radionavigation–satellite systems on a shared basis with defence applications.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS3', 'The use of the band 1 435–1 535 MHz by the aeronautical mobile service for telemetry has priority over other uses by the mobile service.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS7', 'Operation of stations of the aeronautical mobile (OR) service on a primary basis in Australia is on the condition that harmful interference is not caused to stations of services of other countries operating in accordance with the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS9', 'The bands 4 152–4 172 kHz, 6 233–6 261 kHz, 8 300–8 340 kHz, 368–12 420 kHz, 16 549–16 617 kHz, 18 846–18 870 kHz, 22 180– 240 kHz and 25 121–25 161.25 kHz are designated to be used principally for the purposes of defence. The Department of Defence is normally consulted in considering non-defence use of these bands.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS10', 'Operation of stations of the aeronautical mobile (OR) service on a secondary basis in Australia is on the condition that harmful interference is not caused to stations of services of other countries operating in accordance with the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS12', 'Operation of the amateur service in the band 7 100–7 300 kHz is subject to the conditions of Radio Regulation No. 4.4.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS24', 'The introduction of new stations of the broadcasting service in the band 85–87.5 MHz is subject to special agreements between Australia and other administrations. Television services operating in this band may be transferred to other broadcasting bands.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS25', 'Operation of the aeronautical mobile (R) service in the bands 108– 117.975 MHz and 117.975–137 MHz, and of the aeronautical radionavigation service in the bands 74.8–75.2 MHz, 108– 117.975 MHz, 328.6–335.4 MHz, 960–1 215 MHz and 5 000– 250 MHz is subject to the provisions of Annex 10 to the Convention on International Civil Aviation and the Standards and Recommended Practices of the International Civil Aviation Organisation (ICAO).');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS26', 'The allocation to the broadcasting service in the band 137–144 MHz will remain until existing stations of that service are transferred to other broadcasting bands. No new assignments will be made to broadcasting services in this band.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS29', 'In these bands the radiolocation service is primary in offshore areas. Australian Radiofrequency Spectrum Plan 2021 107');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS32', 'The band 918–926 MHz (centre frequency 922 MHz) is designated for industrial, scientific and medical (ISM) applications. Radiocommunication stations operating within this band must accept harmful interference which may be caused by these applications. ISM equipment operating in this band is subject to the provisions of Radio Regulation No. 15.13.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS49', 'The use and assignment of frequencies to non-directional beacons (NDBs) of the aeronautical radionavigation service in the bands 190– kHz, 415–495 kHz, 505–526.5 kHz and 1 606.5–1 800 kHz shall take account of Annex 10 to the Convention on International Civil Aviation and the Standards and Recommended Practices of the International Civil Aviation Organisation (ICAO).');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS50', 'The use of the bands 526.5–535 kHz and 535–1 606.5 kHz by the broadcasting service shall take into account the provisions of the Final Acts of the Regional Administrative LF/MF Broadcasting Conference (Regions 1 and 3), Geneva, 1975.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS51', 'Use of the bands 2 850–3 025 kHz, 3 400–3 500 kHz, 4 650–4 700 kHz, 480–5 680 kHz, 6 525–6 685 kHz, 8815–8 965 kHz, 10 005– 100 kHz, 11 275–11 400 kHz, 13 260–13 360 kHz, 17 900– 970 kHz and 21 924–22 000 kHz by the aeronautical mobile (R) service is subject to the provisions of Appendix 27 of the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS52', 'Chapter VIII and other provisions of the Radio Regulations are applicable to the use of the bands 3 025–3 155 kHz, 3 900–3 950 kHz, 700–4 750 kHz, 5 450–5 480 kHz, 5 680–5 730 kHz, 6 685– 765 kHz, 8 965–9 040 kHz, 11 175–11 275 kHz, 13 200–13 260 kHz, 060–15 100 kHz, 17 970–18 030 kHz and 23 200–23 350 kHz by the aeronautical mobile (OR) service.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS53', 'The provisions of Appendix 17 and Chapter IX of the Radio Regulations apply to the use of the bands 4 063–4 438 kHz, 6 200–6 525 kHz, 195–8 815 kHz, 12 230–13 200 kHz, 16 360–17 410 kHz, 18 780– 800 kHz, 22 000–22 855 kHz and 25 070–26 175 kHz only where allocated to the maritime mobile service.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS54', 'The use of the bands 5 950–6 200 kHz, 7 200–7 300 kHz, 9 500– 900 kHz, 11 650–12 050 kHz, 13 600–13 800 kHz, 15 100– 600 kHz, 17 550–17 900 kHz, 21 450–21 850 kHz and 25 670– 100 kHz by the broadcasting service shall be in accordance with the provisions of Articles 11 and 12 of the Radio Regulations. Australian Radiofrequency Spectrum Plan 2021 108');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS57', 'This band may be used by stations of the radiolocation service for the purposes of defence, on condition that harmful interference is not caused to other services operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS58', 'This band may be used by stations of the fixed and mobile services for the purposes of defence on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS59', 'Stations of the fixed and mobile services used for the purposes of defence may use the frequency bands specified in AUS9 on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS62', 'Parts of this band might be used in the future for the purposes of defence.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS64', 'The band 960–1 215 MHz may be used by stations of the fixed and mobile services using spread spectrum modulation for the purposes of defence on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS65', 'Geographical and operational constraints will apply to the mobile– satellite service when observations are being made by the Australia Telescope in the 1 660 MHz–1 660.5 MHz band.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS66', 'The band 151.4125–153 MHz is also allocated to the radiodetermination service on a secondary basis.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS67', 'Tropospheric scatter systems used for the purposes of defence may operate in the bands between 4 400 and 5 000 MHz. The possible requirement to coordinate with the fixed–satellite service should be noted (see International Footnote No. 441 at Part 4 of this Spectrum Plan).');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS68', 'Underground mine communications systems are authorised to operate in the bands designated by this footnote on the condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS73', 'The provisions of No. 52.220 and Appendix 17 of the Radio Regulations are applicable to the use of the band 8 100–8 195 kHz by the maritime mobile service. Australian Radiofrequency Spectrum Plan 2021 109');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS74', 'The use of the bands 526.5–535 kHz and 535–1 606.5 kHz by the fixed service shall be subject to the condition that no harmful interference shall be caused to the reception of transmissions by stations of the broadcasting service operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS75', 'Use of this service by stations shall be subject to the condition that no harmful interference is caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS87', 'Radio astronomy facilities operated by the CSIRO at the Paul Wild Observatory Narrabri (latitude 30° 18'' 46.40" S, longitude 149° 33'' 0.44" E), the Parkes Observatory (latitude 32° 59'' 54.25" S, longitude 148° 15'' 48.65" E) and the Mopra Observatory Coonabarabran (latitude 31° 16'' 04.12" S, longitude 149° 05'' 58.72" E) and by the University of Tasmania at the Mount Pleasant Observatory Hobart (latitude 42° 48'' 12.92" S, longitude 147° 26'' 25.86" E) and the Ceduna Observatory (latitude 31° 52'' 03.69" S, longitude 133° 48'' 35.40" E), and at the Canberra Deep Space Communication Complex (latitude 35° 23'' 54.46" S, longitude 148° 58'' 39.66" E) conduct passive observations in the frequency bands 1.2–1.8 GHz, 2.2–2.7 GHz, 4.5–6.7 GHz, 8–10 GHz and 16–26 GHz using receivers that are highly sensitive to interference. The Paul Wild and Mopra observatories also operate in the bands 30– GHz and 75–115 GHz.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS88', 'In the band 12.2–12.5 GHz, transponders on space stations of the fixed– satellite service may be used additionally for transmissions in the broadcasting-satellite service. Such emissions shall comply with the power flux density limits prescribed for the fixed–satellite service in this band.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS89', 'Use of the band 54–56 MHz by the radiolocation service is limited to wind profiler radars (see Resolution 217 (WRC-97)).');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS90', 'In consideration of Resolution 217 (WRC-97), the use by wind profiler radars is confined to the sub-bands 448–450 MHz and 1 270– 295 MHz.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS91', 'Use of the mobile service is limited to Australian, State and Territory Government purposes. The Department of Defence is normally consulted in considering non-defence use of this service.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS92', 'The band 202.9–203.1 MHz may be used by stations of the space operation service (space-to-Earth) on condition that harmful interference is not caused to stations of the services allocated in this band. Australian Radiofrequency Spectrum Plan 2021 110');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS93', 'The band may be used by stations of the aeronautical mobile (OR) service for the purposes of defence on condition that harmful interference will not be caused to stations of the space research (deep space)(space-to-Earth) service in this band.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS94', 'The following bands are intended to be used principally for the purposes of defence: 420.8–421.2 MHz, 424.8–425.2 MHz, 427.8–428.2 MHz. The Department of Defence is normally consulted in considering non- defence use of these bands.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS95', 'This band may be used by stations of the fixed and mobile services for the purposes of defence on condition that harmful interference is not caused to stations of other services allocated in this band.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS96', 'This band may be used by stations of the fixed service on condition that harmful interference is not caused to stations of other services operating in accordance with this Spectrum Plan or the Radio Regulations.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS98', 'The harmonised frequency ranges in the 400 MHz band are used for national security, law enforcement, and first and second responder agencies. These agencies include police, fire, ambulance, and emergency rescue. These agencies are normally consulted about use of this spectrum for government purposes via the Commonwealth, State and Territory representative arrangements established by the National Coordinating Committee for Government Radiocommunications2. The harmonised band comprises the following frequency ranges: 403–403.98125 MHz, 405.01875–406 MHz, 408.64375–410.54375 MHz, 412.46875–413.43125 MHz, 414.46875–415.44375 MHz, 418.09375–430 MHz, 457.50625–459.9875 MHz, 467.50625–469.9875 MHz. The National Coordinating Committee for Government Radiocommunications (NCCGR) is a standing representative committee of the National Emergency Management Committee and was established by agreement of First Ministers in 2004 and replaced the Inter-Government Spectrum Harmonisation Committee (ISHC). It was formed to support a national will to address the core issues of spectrum and inter-jurisdictional operations and to ensure that the relevant issues are considered and discussed within a national framework. The NCCGR consists of representatives from Australian jurisdictions and Australian Government Departments and has been formed with the endorsement of jurisdiction Premiers/Chief Ministers (see Preamble, Constitution of the NCCGR March 2012). Australian Radiofrequency Spectrum Plan 2021 111');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS99', 'The band 420.8–421.2 MHz is also allocated to the amateur service on a secondary basis.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS100', 'This band is designated for use by the Australian Defence Force and Department of Defence. The Department of Defence is to be consulted in considering non-defence use of this band.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS100A', 'This service is designated for use by the Australian Defence Force and Department of Defence. The Department of Defence is to be consulted in considering non-defence use of this service.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS101', 'This band is designated to be used principally for the purposes of defence and national security. The Department of Defence is normally consulted in considering non-defence use of this band.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS101A', 'This service is designated to be used principally for the purposes of defence and national security. The Department of Defence is normally consulted in considering non-defence use of this service.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS102', 'This band is intended to be used principally for the purposes of defence of Australia, law enforcement and emergency services.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS102A', 'This service is intended to be used principally for the purposes of defence of Australia, law enforcement and emergency services.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS103', 'The Murchison Radioastronomy Observatory (MRO) (latitude 26° 42'' 10.4" S, longitude 116° 39'' 37.0" E) hosts the Australian Square Kilometre Array Pathfinder (ASKAP) operating in the band 700– 800 MHz and the Murchison Widefield Array (MWA) operating in the band 80–300 MHz.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS104', 'Under subsection 31(1) of the Act parts of the radiofrequency spectrum, including the band 520–694 MHz, are designated as being primarily for broadcasting purposes and referred for planning in accordance with Part of the Broadcasting Services Act 1992.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS105', 'This band may be used by stations of the radiolocation service for meteorological and aeronautical surveillance radar, on condition that potential harmful interference is accepted from services operating in adjacent bands in accordance with a spectrum licence.');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS106', 'The band 2103.406-2109.406 MHz may be used by the space operation (space-to-Earth), space research (space-to-Earth) and Earth exploration-satellite (space-to-Earth) services to support the operation of the Bilateration Ranging Transponder System earth station facility near Alice Springs (latitude 23° 45'' 25.3" S, longitude 133° 52'' 58.2" E) Australian Radiofrequency Spectrum Plan 2021 112');
INSERT INTO spectrum_australian_footnotes(footnote_ref, footnote_text) VALUES('AUS106A', 'The band 2284.5–2290.5 MHz may be used by the space operation (Earth-to-space), space research (Earth-to-space) and Earth exploration-satellite (Earth-to-space) services to support the operation of the Bilateration Ranging Transponder System earth station facility near Alice Springs (latitude 23° 45'' 25.3" S, longitude 133° 52'' 58.2" E) Australian Radiofrequency Spectrum Plan 2021 113');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('54A', 'Use of the 8.3–11.3 kHz frequency band by stations in the meteorological aids service is limited to passive use only. In the band 9–11.3 kHz, meteorological aids stations shall not claim protection from stations of the radionavigation service submitted for notification to the Bureau prior to 1 January 2013. For sharing between stations of the meteorological aids service and stations in the radionavigation service submitted for notification after this date, the most recent version of Recommendation ITU-R RS.1881 should be applied.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('54B', 'Additional allocation: in Algeria, Saudi Arabia, Bahrain, Egypt, the United Arab Emirates, the Russian Federation, Iran (Islamic Republic of), Iraq, Kuwait, Lebanon, Morocco, Qatar, the Syrian Arab Republic, Sudan and Tunisia, the frequency band 8.3– kHz is also allocated to the radionavigation, fixed and mobile services on a primary basis. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('54C', 'Additional allocation: in China, the frequency band 8.3–9 kHz is also allocated to the maritime radionavigation and maritime mobile services on a primary basis. Additional allocation: in Armenia, the Russian Federation, Georgia, Kyrgyzstan, Tajikistan, and Turkmenistan, the frequency band 14–17 kHz is also allocated to the radionavigation service on a primary basis. ( ) WRC-15 The stations of services to which the bands 14–19.95 kHz and 20.05–70 kHz and in Region 1 also the bands 72–84 kHz and 86–90 kHz are allocated may transmit standard frequency and time signals. Such stations shall be afforded protection from harmful interference. In Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Kyrgyzstan, Tajikistan and Turkmenistan, the frequencies 25 kHz and kHz will be used for this purpose under the same conditions. ( ) WRC-12 The use of the bands 14–19.95 kHz, 20.05–70 kHz and 70–90 kHz (72–84 kHz and 86– kHz in Region 1) by the maritime mobile service is limited to coast radiotelegraph stations (A1A and F1B only). Exceptionally, the use of class J2B or J7B emissions is authorised subject to the necessary bandwidth not exceeding that normally used for class A1A or F1B emissions in the band concerned. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('114', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('70', '–72 kHz and 84–86 kHz to the fixed and maritime mobile services is on a primary basis (see No. 33). ( ) WRC-2000 In the bands 70–90 kHz (70–86 kHz in Region 1) and 110–130 kHz (112–130 kHz in Region 1), pulsed radionavigation systems may be used on condition that they do not cause harmful interference to other services to which these bands are allocated. In Region 2, the establishment and operation of stations in the maritime radionavigation service in the bands 70–90 kHz and 110–130 kHz shall be subject to agreement obtained under No. 9.21 with administrations whose services, operating in accordance with the Table, may be affected. However, stations of the fixed, maritime mobile and radiolocation services shall not cause harmful interference to stations in the maritime radionavigation service established under such agreements. Administrations which operate stations in the radionavigation service in the band 90– kHz are urged to coordinate technical and operating characteristics in such a way as to avoid harmful interference to the services provided by these stations. Only classes A1A or F1B, A2C, A3C, F1C or F3C emissions are authorised for stations of the fixed service in the bands allocated to this service between 90 kHz and 160 kHz (148.5 kHz in Region 1) and for stations of the maritime mobile service in the bands allocated to this service between 110 kHz and 160 kHz (148.5 kHz in Region 1). Exceptionally, class J2B or J7B emissions are also authorised in the bands between kHz and 160 kHz (148.5 kHz in Region 1) for stations of the maritime mobile service. Different category of service: in Bangladesh, the allocation of the bands 112–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('117', '.6 kHz and 126–129 kHz to the fixed and maritime mobile services is on a primary basis (see No. 33). (WRC-2000) Different category of service: in Germany, the allocation of the band 115–117.6 kHz to the fixed and maritime mobile services is on a primary basis (see No. 33) and to the radionavigation service on a secondary basis (see No. 32). Additional allocation: in Kyrgyzstan, and Turkmenistan, the frequency band 130–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('148', '.5 kHz is also allocated to the radionavigation service on a secondary basis. Within and between these countries this service shall have an equal right to operate. (WRC-19)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('67A', 'Stations in the amateur service using frequencies in the band 135.7–137.8 kHz shall not exceed a maximum radiated power of 1 W (e.i.r.p) and shall not cause harmful interference to stations of the radionavigation service operating in countries listed in No. 67. (WRC-07) Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('115', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('67B', 'The use of the frequency band 135.7–137.8 kHz in Algeria, Egypt, Iraq, Lebanon, Syrian Arab Republic, Sudan, South Sudan and Tunisia is limited to the fixed and maritime mobile services. The amateur service shall not be used in the above-mentioned countries in the frequency band 135.7–137.8 kHz, and this should be taken into account by the countries authorising such use. (WRC-19) Alternative allocation: in Congo (Rep. of the), the Dem. Rep. of the Congo and South Africa, the frequency band 160–200 kHz is allocated to the fixed service on a primary basis. (WRC-15) Additional allocation: in Somalia, the band 200–255 kHz is also allocated to the aeronautical radionavigation service on a primary basis. Alternative allocation: in Angola, Botswana, Burundi, the Central African Rep., Congo (Rep. of the), Eswatini, Ethiopia, Kenya, Lesotho, Madagascar, Malawi, Mozambique, Namibia, Nigeria, Oman, the Dem. Rep. of the Congo, South Africa, Tanzania, Chad, Zambia and Zimbabwe, the frequency band 200–283.5 kHz is allocated to the aeronautical radionavigation service on a primary basis. (WRC-19) The band 285–325 kHz (283.5–325 kHz in Region 1), in the maritime radionavigation service may be used to transmit supplementary navigational information using narrow- band techniques, on condition that no harmful interference is caused to radiobeacon stations operating in the radionavigation service. (WRC-97) Additional Allocation: in Region 1, the frequency band 285.3–285.7 kHz is also allocated to the maritime radionavigation service (other than radiobeacons) on a primary basis. Different category of service: in Armenia, Azerbaijan, Belarus, Georgia, Moldova, Kyrgyzstan, the Russian Federation, Tajikistan, Turkmenistan, Ukraine and the Black Sea areas of Romania, the allocation of the band 315–325 kHz to the maritime radionavigation service is on a primary basis under the condition that in the Baltic Sea area, the assignment of frequencies in this band to new stations in the maritime or aeronautical radionavigation services shall be subject to prior consultation between the administrations concerned. (WRC-07) The frequency 410 kHz is designated for radio direction-finding in the maritime radionavigation service. The other radionavigation services to which the band 405– kHz is allocated shall not cause harmful interference to radio direction-finding in the band 406.5–413.5 kHz. Different category of service: in Australia, China, the French overseas communities of Region 3, Korea (Rep. of), India, Iran (Islamic Republic of), Japan, Pakistan, Papua New Guinea, the Dem. People’s Rep. of Korea and Sri Lanka, the allocation of the frequency band 415–495 kHz to the aeronautical radionavigation service is on a primary basis. In Armenia, Azerbaijan, Belarus, the Russian Federation, Kazakhstan, Latvia, Uzbekistan and Kyrgyzstan, the allocation of the frequency band 435–495 kHz Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('116', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('79A', 'When establishing coast stations in the NAVTEX service on the frequencies 490 kHz, kHz and 4 209.5 kHz, administrations are strongly recommended to coordinate the operating characteristics in accordance with the procedures of the International Maritime Organisation (IMO) (see Resolution 339 (Rev.WRC-07)). ( ) WRC-07 In Region 2, the use of the band 435–495 kHz by the aeronautical radionavigation service is limited to non-directional beacons not employing voice transmission.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('80A', 'The maximum equivalent isotropically radiated power (e.i.r.p.) of stations in the amateur service using frequencies in the band 472–479 kHz shall not exceed 1 W. Administrations may increase this limit of e.i.r.p. to 5 W in portions of their territory which are at a distance of over 800 km from the borders of Algeria, Saudi Arabia, Azerbaijan, Bahrain, Belarus, China, Comoros, Djibouti, Egypt, United Arab Emirates, the Russian Federation, Iran (Islamic Republic of), Iraq, Jordan, Kazakhstan, Kuwait, Lebanon, Libya, Morocco, Mauritania, Oman, Uzbekistan, Qatar, Syrian Arab Republic, Kyrgyzstan, Somalia, Sudan, Tunisia, Ukraine and Yemen. In this frequency band, stations on the amateur service shall not cause harmful interference to, or claim protection from, stations of the aeronautical radionavigation service.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('80B', 'The use of the frequency band 472–479 kHz in Algeria, Saudi Arabia, Azerbaijan, Bahrain, Belarus, China, Comoros, Djibouti, Egypt, United Arab Emirates, the Russian Federation, Iraq, Jordan, Kazakhstan, Kuwait, Lebanon, Libya, Mauritania, Oman, Uzbekistan, Qatar, Syrian Arab Republic, Kyrgyzstan, Somalia, Sudan, Tunisia, and Yemen is limited to the maritime mobile and aeronautical radionavigation services. The amateur service shall not be used in the above-mentioned countries in this frequency band, and this should be taken into account by the countries authorising such use. In the maritime mobile service, the frequency 490 kHz is to be used exclusively for the transmission by coast stations of navigational and meteorological warnings and urgent information to ships, by means of narrow-band direct-printing telegraphy. The conditions for use of the frequency 490 kHz are prescribed in Articles 31 and 52. In using the band 415–495 kHz for the aeronautical radionavigation service, administrations are requested to ensure that no harmful interference is caused to the Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('82C', 'The frequency band 495–505 kHz is used for the international NAVDAT system as described in the most recent version of Recommendation ITU-R M.2010. NAVDAT transmitting stations are limited to coast stations. ( ) WRC-19 The conditions for the use of the frequency 518 kHz by the maritime mobile service are prescribed in Articles 31 and 52 ( ) WRC-07 In Region 2, in the band 525–535 kHz the carrier power of broadcasting stations shall not exceed 1 kW during the day and 250 W at night. Additional allocation: in Angola, Botswana, Eswatini, Lesotho, Malawi, Mozambique, Namibia and Niger, the frequency band 526.5–535 kHz is also allocated to the mobile service on a secondary basis. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('87A', 'Additional allocation: in Uzbekistan, the band 526.5–1 606.5 kHz is also allocated to the radionavigation service on a primary basis. Such use is subject to agreement obtained under No. 9.21 with administrations concerned and limited to ground-based radiobeacons in operation on 27 October 1997 until the end of their lifetime. ( ) WRC-97 Additional allocation: in China, the band 526.5–535 kHz is also allocated to the aeronautical radionavigation service on a secondary basis. In Region 2, the use of the band 1 605–1 705 kHz by stations of the broadcasting service is subject to the Plan established by the Regional Administrative Radio Conference (Rio de Janeiro, 1988). The examination of frequency assignments to stations of the fixed and mobile services in the band 1 625–1 705 kHz shall take account of the allotments appearing in the Plan established by the Regional Administrative Radio Conference (Rio de Janeiro, 1988). In the band 1 605–1 705 kHz, in cases where a broadcasting station of Region 2 is concerned, the service area of the maritime mobile stations in Region 1 shall be limited to that provided by ground-wave propagation. Additional allocation: in the Philippines and Sri Lanka, the band 1 606.5–1 705 kHz is also allocated to the broadcasting service on a secondary basis. ( ) WRC-97 Some countries of Region 1 use radiodetermination systems in the bands 1 606.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('625', 'kHz, 1 635–1 800 kHz, 1 850–2 160 kHz, 2 194–2 300 kHz, 2 502–2 850 kHz and 3 500–3 800 kHz, subject to agreement obtained under No. 9.21. The radiated mean power of these stations shall not exceed 50 W. Additional allocation: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Hungary, Kazakhstan, Latvia, Lithuania, Mongolia, Nigeria, Uzbekistan, Poland, Kyrgyzstan, Slovakia, Tajikistan, Chad, Turkmenistan and Ukraine, the Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('118', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('850', 'kHz or 1 950 kHz. Alternative allocation: in Armenia, Azerbaijan, Belarus, Belgium, Cameroon, Congo (Rep. of the), Denmark, Egypt, Eritrea, Spain, Ethiopia, the Russian Federation, Georgia, Greece, Italy, Kazakhstan, Lebanon, Lithuania, the Syrian Arab Republic, Kyrgyzstan, Somalia, Tajikistan, Tunisia, Turkmenistan and Turkey, the frequency band 1 810–1 830 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-15 Additional allocation: in Saudi Arabia, Austria, Iraq, Libya, Uzbekistan, Slovakia, Romania, Slovenia, Chad, and Togo, the band 1 810–1 830 kHz is also allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-12 In Region 1, the authorisation to use the band 1 810–1 830 kHz by the amateur service in countries situated totally or partially north of 40° N shall be given only after consultation with the countries mentioned in Nos. 98 and 99 to define the necessary steps to be taken to prevent harmful interference between amateur stations and stations of other services operating in accordance with Nos. 98 and 99. Alternative allocation: in Bolivia, Chile, Paraguay and Peru, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('119', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('096', '.5 kHz, 2 100.0 kHz and 2 103.5 kHz. In Argentina and Uruguay, the carrier frequencies 2 068.5 kHz and 2 075.5 kHz are also used for this purpose, while the frequencies within the band 2 072–2 075.5 kHz are used as provided in No. 52.165. In Regions 2 and 3, provided no harmful interference is caused to the maritime mobile service, the frequencies between 2 065 kHz and 2 107 kHz may be used by stations of the fixed service communicating only within national borders and whose mean power does not exceed 50 W. In notifying the frequencies, the attention of the Bureau should be drawn to these provisions. Additional allocation: in Saudi Arabia, Eritrea, Eswatini, Ethiopia, Iraq, Libya and Somalia, the frequency band 2 160–2 170 kHz is also allocated to the fixed and mobile, except aeronautical mobile (R), services on a primary basis. The mean power of stations in these services shall not exceed 50 W. ( ) WRC-19 The carrier frequency 2 182 kHz is an international distress and calling frequency for radiotelephony. The conditions for the use of the band 2 173.5–2 190.5 kHz are prescribed in Articles 31 and 52. ( ) WRC-07 The frequencies 2 187.5 kHz, 4 207.5 kHz, 6 312 kHz, 8 414.5 kHz, 12 577 kHz and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('804', '.5 kHz are international distress frequencies for digital selective calling. The conditions for the use of these frequencies are prescribed in Article 31. The frequencies 2 174.5 kHz, 4 177.5 kHz, 6 268 kHz, 8 376.5 kHz, 12 520 kHz and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('695', 'kHz are international distress frequencies for narrow-band direct-printing telegraphy. The conditions for the use of these frequencies are prescribed in Article 31. The carrier frequencies 2 182 kHz, 3 023 kHz, 5 680 kHz, 8 364 kHz and the frequencies 121.5 MHz, 156.525 MHz, 156.8 MHz and 243 MHz may also be used, in accordance with the procedures in force for terrestrial radiocommunication services, for search and rescue operations concerning manned space vehicles. The conditions for the use of the frequencies are prescribed in Article 31. The same applies to the frequencies 10 003 kHz, 14 993 kHz and 19 993 kHz, but in each of these cases emissions must be confined in a band of ±3 kHz about the frequency. ( ) WRC-07 Alternative allocation: in Sri Lanka, the frequency band 2 194–2 300 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('120', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('200', '–3 400 kHz, 4 750–4 995 kHz and 5 005–5 060 kHz by the broadcasting service, see Nos. 16 to 20, 21 and 23.3 to 23.10. Alternative allocation: in Iraq, the frequency band 2 502–2 625 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19 The carrier (reference) frequencies 3 023 kHz and 5 680 kHz may also be used, in accordance with Article 31, by stations of the maritime mobile service engaged in coordinated search and rescue operations. ( ) WRC-07 Administrations are urged to authorise the use of the band 3 155–3 195 kHz to provide a common worldwide channel for low power wireless hearing aids. Additional channels for these devices may be assigned by administrations in the bands between 3 155 kHz and 3 400 kHz to suit local needs. It should be noted that frequencies in the range 3 000 kHz to 4 000 kHz are suitable for hearing aid devices which are designed to operate over short distances within the induction field. Alternative allocation: in Côte d’Ivoire, Egypt, Liberia, Sri Lanka and Togo, the frequency band 3 155–3 200 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19 Additional allocation: in the United States, Mexico and Peru, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('230', '–3 400 kHz is also allocated to the radiolocation service on a secondary basis. ( ) WRC-19 Additional allocation: in Peru, the frequency band 3 500–3 750 kHz is also allocated to the fixed and mobile services on a primary basis. ( ) WRC-15 Alternative allocation: in Bolivia, Chile, Ecuador, Paraguay and Peru, the frequency band 3 750–4 000 kHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-15 Additional allocation: in Botswana, Eswatini, Lesotho, Malawi, Mozambique, Namibia, South Africa, Zambia and Zimbabwe, the frequency band 3 900–3 950 kHz is also allocated to the broadcasting service on a primary basis, subject to agreement obtained under No. 9.21. ( ) WRC-19 Additional allocation: in Greenland, the band 3 950–4 000 kHz is also allocated to the broadcasting service on a primary basis. The power of the broadcasting stations operating in this band shall not exceed that necessary for a national service and shall in no case exceed 5 kW. In Region 3, the stations of those services to which the band 3 995–4 005 kHz is allocated may transmit standard frequency and time signals. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('121', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('438', 'kHz, stations in the fixed service, with a mean power not exceeding 1 kW, can be operated on condition that they are situated at least 600 km from the coast and that harmful interference is not caused to the maritime mobile service. ( ) WRC-19 The conditions for the use of the carrier frequencies 4 125 kHz and 6 215 kHz are prescribed in Articles 31 and 52. ( ) WRC-07 The frequency 4 209.5 kHz is used exclusively for the transmission by coast stations of meteorological and navigational warnings and urgent information to ships by means of narrow-band direct-printing techniques. (WRC-97) The frequencies 4 210 kHz, 6 314 kHz, 8 416.5 kHz, 12 579 kHz, 16 806.5 kHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('680', '.5 kHz, 22 376 kHz and 26 100.5 kHz are the international frequencies for the transmission of Maritime Safety Information (MSI) (see Appendix 17).');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('132A', 'Stations in the radiolocation service shall not cause harmful interference to, or claim protection from, stations operating in the fixed or mobile services. Applications of the radiolocation service are limited to oceanographic radars operating in accordance with Resolution 612 (Rev.WRC-12).');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('132B', 'Alternative allocation: in Armenia, Belarus, Moldova and Kyrgyzstan, the frequency band 4 438–4 488 kHz is allocated to the fixed and mobile, except aeronautical mobile (R), services on a primary basis. ( ) WRC-19 Different category of service: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Latvia, Lithuania, Niger, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the allocation of the band 5 130–5 250 kHz to the mobile, except aeronautical mobile, service is on a primary basis (see No. 33). ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('133A', 'Alternative allocation: in Armenia, Belarus, Moldova and Kyrgyzstan, the frequency bands 5 250–5 275 kHz and 26 200–26 350 kHz are allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('133B', 'Stations in the amateur service using the frequency band 5 351.5–5 366.5 kHz shall not exceed a maximum radiated power of 15 W (e.i.r.p.). However, in Region 2 in Mexico, stations in the amateur service using the frequency band 5 351.5–5 366.5 kHz shall not exceed a maximum radiated power of 20 W (e.i.r.p.). In the following Region 2 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('122', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('366', '.5 kHz shall not exceed a maximum radiated power of 25 W (e.i.r.p.). ( ) WRC-19 The use of the frequency bands 5 900–5 950 kHz, 7 300–7 350 kHz, 9 400–9 500 kHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('600', '–11 650 kHz, 12 050–12 100 kHz, 13 570–13 600 kHz, 13 800–13 870 kHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('19', '). ( ) WRC-19 Additional allocation: frequencies in the band 5 900–5 950 kHz may be used by stations in the following services, communicating only within the boundary of the country in which they are located: fixed service (in all three Regions), land mobile service (in Region 1), mobile except aeronautical mobile (R) service (in Regions 2 and 3), on the condition that harmful interference is not caused to the broadcasting service. When using frequencies for these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. ( ) WRC-07 On condition that harmful interference is not caused to the maritime mobile service, the bands 6 200–6 213.5 kHz and 6 220.5–6 525 kHz may be used exceptionally by stations in the fixed service, communicating only within the boundary of the country in which they are located, with a mean power not exceeding 50 W. At the time of notification of these frequencies, the attention of the Bureau will be drawn to the above conditions. The following bands:');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('765', '–6 795 kHz (centre frequency 6 780 kHz),');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('433', '.05–434.79 MHz (centre frequency 433.92 MHz) in Region 1 except in the countries mentioned in No. 280,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('61', '–61.5 GHz (centre frequency 61.25 GHz),');
