INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('141C', 'In Regions 1 and 3, the band 7 100–7 200 kHz is allocated to the broadcasting service until 29 March 2009 on a primary basis. ( ) WRC-03 Until 29 March 2009, the use of the band 7 100–7 300 kHz in Region 2 by the amateur service shall not impose constraints on the broadcasting service intended for use within Region 1 and Region 3. After 29 March 2009 the use of the band 7 200–7 300 kHz in Region 2 by the amateur service shall not impose constraints on the broadcasting service intended for use within Region 1 and Region 3. ( ) WRC-03 Additional allocation: frequencies in the band 7 300–7 350 kHz may be used by stations in the fixed service and in the land mobile service, communicating only within the boundary of the country in which they are located, on condition that harmful interference is not caused to the broadcasting service. When using frequencies for these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. (WRC-07)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('143A', 'In Region 3, the band 7 350–7 450 kHz is allocated, until 29 March 2009, to the fixed service on a primary basis and to the land mobile service on a secondary basis. After March 2009, frequencies in this band may be used by stations in the above- Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('124', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('143B', 'In Region 1, the band 7 350–7 450 kHz is allocated, until 29 March 2009, to the fixed service on a primary basis and to the land mobile service on a secondary basis. After March 2009, on condition that harmful interference is not caused to the broadcasting service, frequencies in the band 7 350–7 450 kHz may be used by stations in the fixed and land mobile services communicating only within the boundary of the country in which they are located, each station using a total radiated power that shall not exceed dBW. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('143C', 'Additional allocation: after 29 March 2009 in Algeria, Saudi Arabia, Bahrain, Comoros, Djibouti, Egypt, United Arab Emirates, Iran (Islamic Republic of), Jordan, Kuwait, Libya, Morocco, Mauritania, Niger, Oman, Qatar, the Syrian Arab Republic, Sudan, South Sudan, Tunisia and Yemen, the bands 7 350–7 400 kHz and 7 400–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('450', 'kHz are also allocated to the fixed service on a primary basis. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('143D', 'In Region 2, the band 7 350–7 400 kHz is allocated, until 29 March 2009, to the fixed service on a primary basis and to the land mobile service on a secondary basis. After March 2009, frequencies in this band may be used by stations in the above- mentioned services, communicating only within the boundary of the country in which they are located, on condition that harmful interference is not caused to the broadcasting service. When using frequencies for these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('143E', 'Until 29 March 2009, the band 7 450–8 100 kHz is allocated to the fixed service on a primary basis and to the land mobile service on a secondary basis. ( ) WRC-03 In Region 3, the stations of those services to which the band 7 995–8 005 kHz is allocated may transmit standard frequency and time signals. The conditions for the use of the carrier frequencies 8 291 kHz, 12 290 kHz and');
