INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('145A', 'Stations in the radiolocation service shall not cause harmful interference to, or claim protection from, stations operating in the fixed service. Applications of the radiolocation service are limited to oceanographic radars operating in accordance with Resolution 612 (Rev.WRC-12).');
