INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('24', '–24.25 GHz (centre frequency 24.125 GHz) are also designated for industrial, scientific and medical (ISM) applications. Radiocommunication services operating within these bands must accept harmful interference which may be caused by these applications. ISM equipment operating in these bands is subject to the provisions of No. 15.13. Additional allocation: frequencies in the bands 13 570–13 600 kHz and 13 800–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('870', 'kHz may be used by stations in the fixed service and in the mobile except aeronautical mobile (R) service, communicating only within the boundary of the country in which they are located, on the condition that harmful interference is not caused to the broadcasting service. When using frequencies in these services, administrations are urged to use the minimum power required and to take account of the seasonal use of frequencies by the broadcasting service published in accordance with the Radio Regulations. (WRC-07) Additional allocation: in Armenia, Azerbaijan, China, Côte d’Ivoire, the Russian Federation, Georgia, Iran (Islamic Republic of), Kazakhstan, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the band 14 250–14 350 kHz is also allocated to the fixed service on a primary basis. Stations of the fixed service shall not use a radiated power exceeding 24 dBW. ( ) WRC-03 In Region 3, the stations of those services to which the band 15 995–16 005 kHz is allocated may transmit standard frequency and time signals. Additional allocation: in Armenia, Azerbaijan, the Russian Federation, Georgia, Kazakhstan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the band 18 068–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('168', 'kHz is also allocated to the fixed service on a primary basis for use within their boundaries, with a peak envelope power not exceeding 1 kW. ( ) WRC-03 Additional allocation: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Moldova, Mongolia, Uzbekistan, Kyrgyzstan, Slovakia, Tajikistan, Turkmenistan and Ukraine, the band 21 850–21 870 kHz is also allocated to the aeronautical mobile (R) service on a primary basis. ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('155A', 'In Armenia, Azerbaijan, Belarus, Georgia, Kazakhstan, Moldova, Mongolia, Uzbekistan, Kyrgyzstan, Slovakia, the Russian Federation, Tajikistan, Turkmenistan and Ukraine, the use of the band 21 850–21 870 kHz by the fixed service is limited to provision of services related to aircraft flight safety. ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('155B', 'The band 21 870–21 924 kHz is used by the fixed service for provision of services related to aircraft flight safety. Additional allocation: in Nigeria, the band 22 720–23 200 kHz is also allocated to the meteorological aids service (radiosondes) on a primary basis. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('127', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('156A', 'The use of the band 23 200–23 350 kHz by the fixed service is limited to provision of services related to aircraft flight safety. The use of the band 23 350–24 000 kHz by the maritime mobile service is limited to inter-ship radiotelegraphy. Alternative allocation: in Armenia, Belarus, Moldova and Kyrgyzstan, the frequency band 24 450–24 600 kHz is allocated to the fixed and land mobile services on a primary basis. (WRC-19) Alternative allocation: in Armenia, Belarus, Moldova and Kyrgyzstan, the frequency band 39–39.5 MHz is allocated to the fixed and mobile services on a primary basis. ( ) WRC-19 Additional allocation: in Botswana, Burundi, Dem. Rep. of the Congo and Rwanda, the band 41–44 MHz is also allocated to the aeronautical radionavigation service on a primary basis. ( ) WRC-12 Additional allocation: in Iran (Islamic Republic of) and Japan, the band 41–44 MHz is also allocated to the radiolocation service on a secondary basis.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('161A', 'Additional allocation: in Korea (Rep. of), the United States and Mexico, the frequency bands 41.015–41.665 MHz and 43.35–44 MHz are also allocated to the radiolocation service on a primary basis. Stations in the radiolocation service shall not cause harmful interference to, or claim protection from, stations operating in the fixed or mobile services. Applications of the radiolocation service are limited to oceanographic radars operating in accordance with Resolution 612 (Rev.WRC-12). ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('161B', 'Alternative allocation: in Albania, Germany, Armenia, Austria, Belarus, Belgium, Bosnia and Herzegovina, Cyprus, Vatican, Croatia, Denmark, Spain, Estonia, Finland, France, Greece, Hungary, Ireland, Iceland, Italy, Latvia, Liechtenstein, Lithuania, Luxembourg, North Macedonia, Malta, Moldova, Monaco, Montenegro, Norway, Uzbekistan, Netherlands, Portugal, Kyrgyzstan, Slovakia, Czech Rep., Romania, United Kingdom, San Marino, Slovenia, Sweden, Switzerland, Turkey and Ukraine, the frequency band 42–42.5 MHz is allocated to the fixed and mobile services on a primary basis. ( ) WRC-19 Additional allocation: in Australia, the band 44–47 MHz is also allocated to the broadcasting service on a primary basis. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('162A', 'Additional allocation: in Germany, Austria, Belgium, Bosnia and Herzegovina, China, Vatican, Denmark, Spain, Estonia, the Russian Federation, Finland, France, Ireland, Iceland, Italy, Latvia, Liechtenstein, Lithuania, Luxembourg, North Macedonia, Monaco, Montenegro, Norway, the Netherlands, Poland, Portugal, the Czech Rep., the United Kingdom, Serbia, Slovenia, Sweden and Switzerland the frequency band 46– MHz is also allocated to the radiolocation service on a secondary basis. This use is limited to the operation of wind profiler radars in accordance with Resolution 217 (WRC-97). ( ) WRC-19 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('128', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('166A', 'Different category of service: in Austria, Cyprus, the Vatican, Croatia, Denmark, Spain, Finland, Hungary, Latvia, the Netherlands, the Czech Republic, the United Kingdom, Slovakia and Slovenia, the frequency band 50.0–50.5 MHz is allocated to the amateur service on a primary basis. Stations in the amateur service in these countries shall not cause harmful interference to, or claim protection from, stations of the broadcasting, fixed and mobile services operating in accordance with the Radio Regulations in the frequency band 50.0–50.5 MHz in the countries not listed in this provision. For a station of these services, the protection criteria in No. 169B shall also apply. In Region 1, with the exception of those countries listed in No. 169, wind profiler radars operating in the radiolocation service under No. 162A are authorized to operate on the basis of equality with stations in the amateur service in the frequency band 50.0–50.5 MHz. ( WRC-19 )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('166B', 'In Region 1, stations in the amateur service operating on a secondary basis shall not cause harmful interference to, or claim protection from, stations of the broadcasting service. The field strength generated by an amateur station in Region 1 in the frequency band 50–52 MHz shall not exceed a calculated value of +6 dB(μV/m) at a height of m above ground for more than 10% of time along the border of a country with operational analogue broadcasting stations in Region 1 and of neighbouring countries with broadcasting stations in Region 3 listed in Nos. 167 and 168. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('166C', 'In Region 1, stations in the amateur service in the frequency band 50–52 MHz, with the exception of those countries listed in No. 169, shall not cause harmful interference to, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('129', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('166D', 'Different category of service: in Lebanon, the frequency band 50–52 MHz is allocated to the amateur service on a primary basis. Stations in the amateur service in Lebanon shall not cause harmful interference to, or claim protection from, stations of the broadcasting, fixed and mobile services operating in accordance with the Radio Regulations in the frequency band 50–52 MHz in the countries not listed in this provision. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('166E', 'In the Russian Federation, only the frequency band 50.080–50.280 MHz is allocated to the amateur service on a secondary basis. The protection criteria for the other services in the countries not listed in this provision are specified in Nos. 166B and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('169B', '. ( ) WRC-19 Alternative allocation: in Bangladesh, Brunei Darussalam, India, Iran (Islamic Republic of), Pakistan and Singapore, the frequency band 50–54 MHz is allocated to the fixed, mobile and broadcasting services on a primary basis. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('167A', 'Additional allocation: in Indonesia and Thailand, the frequency band 50–54 MHz is also allocated to the fixed, mobile and broadcasting services on a primary basis. (WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('15', ') Additional allocation: in Australia, China and the Dem. People''s Rep. of Korea, the band 50–54 MHz is also allocated to the broadcasting service on a primary basis. Alternative allocation: in Botswana, Eswatini, Lesotho, Malawi, Namibia, Rwanda, South Africa, Zambia and Zimbabwe, the frequency band 50–54 MHz is allocated to the amateur service on a primary basis. In Senegal, the frequency band 50–51 MHz is allocated to the amateur service on a primary basis. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('169A', 'Alternative allocation: in the following countries in Region 1: Angola, Saudi Arabia, Bahrain, Burkina Faso, Burundi, the United Arab Emirates, Gambia, Jordan, Kenya, Kuwait, Mauritius, Mozambique, Oman, Uganda, Qatar, South Sudan and Tanzania, the frequency band 50–54 MHz is allocated to the amateur service on a primary basis. In Guinea-Bissau, the frequency band 50.0–50.5 MHz is allocated to the amateur service on a primary basis. In Djibouti, the frequency band 50–52 MHz is allocated to the amateur service on a primary basis. With the exception of those countries listed in No. 169, stations in the amateur service operating in Region 1 under this footnote, in all or part of the frequency band 50–54 MHz, shall not cause harmful interference to, or claim protection from, stations of other services operating in accordance with the Radio Regulations in Algeria, Egypt, Iran (Islamic Republic of), Iraq, Israel, Libya, Palestine, the Syrian Arab Republic, the Dem. People’s Republic of Korea, Sudan and Tunisia. The field strength generated by an amateur station in the frequency band 50– MHz shall not exceed a value of +6 dB(μV/m) at a height of 10 m above ground for  Pursuant to Resolution 99 (Rev. Dubai, 2018) and taking into account the Israeli-Palestinian Interim Agreement of 28 September 1995. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('130', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('1', ', in all or part of the 50–54 MHz frequency band, shall not cause harmful interference to, or claim protection from, stations of other services used in accordance with the Radio Regulations in Algeria, Armenia, Azerbaijan, Belarus, Egypt, Russian Federation, Iran (Islamic Republic of), Iraq, Kazakhstan, Kyrgyzstan, Libya, Uzbekistan, Palestine*, the Syrian Arab Republic, Sudan, Tunisia and Ukraine. The field strength generated by an amateur station in the frequency band 50–54 MHz shall not exceed a value of +6 dB(μV/m) at a height of 10 m above ground for more than');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('10', '% of time along the borders of the countries listed in this provision. ( ) WRC-19 Additional allocation: in New Zealand, the frequency band 51–54 MHz is also allocated to the fixed and mobile services on a primary basis. ( ) WRC-15 Additional allocation: in Botswana, Eswatini, Lesotho, Malawi, Mali, Namibia, Dem. Rep. of the Congo, Rwanda, South Africa, Zambia and Zimbabwe, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('54', '–68 MHz is also allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( WRC-19) Different category of service: in the French overseas departments and communities in Region 2 and Guyana, the allocation of the frequency band 54–68 MHz to the fixed and mobile services is on a primary basis (see No. 33). ( ) WRC-15 Different category of service: in the French overseas departments and communities in Region 2 and Guyana, the allocation of the frequency band 68–72 MHz to the fixed and mobile services is on a primary basis (see No. 33). ( ) WRC-15 Alternative allocation: in Armenia, Azerbaijan, Belarus, Georgia, Kazakhstan, Moldova, Uzbekistan, Kyrgyzstan, the Russian Federation, Tajikistan, Turkmenistan and Ukraine, the bands 68–73 MHz and 76–87.5 MHz are allocated to the broadcasting service on a primary basis. In Latvia and Lithuania, the bands 68–73 MHz and 76–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('87', '.5 MHz are allocated to the broadcasting and mobile, except aeronautical mobile, services on a primary basis. The services to which these bands are allocated in other countries and the broadcasting service in the countries listed above are subject to agreements with the neighbouring countries concerned. ( ) WRC-07 Additional allocation: in Australia, China, Korea (Rep. of), the Philippines, the Dem. People’s Rep. of Korea and Samoa, the band 68–74 MHz is also allocated to the broadcasting service on a primary basis. ( ) WRC-07 Additional allocation: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kazakhstan, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the band 73–74 MHz is also allocated to the broadcasting service on a primary basis, subject to agreement obtained under No. 9.21. ( ) WRC-07 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('131', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('75', '.2 MHz. Additional allocation: in Egypt, Israel and the Syrian Arab Republic, the band 74.8–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('132', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('104', '–108 MHz is also allocated to the mobile, except aeronautical mobile (R), service on a secondary basis. ( ) WRC-19 Additional allocation: in the Syrian Arab Republic, the band 108–111.975 MHz is also allocated to the mobile service on a secondary basis, subject to agreement obtained under No. 9.21. In order to ensure that harmful interference is not caused to stations of the aeronautical radionavigation service, stations of the mobile service shall not be introduced in the band until it is no longer required for the aeronautical radionavigation service by any administration which may be identified in the application of the procedures invoked under No. 9.21. (WRC-12)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('197A', 'Additional allocation: the band 108–117.975 MHz is also allocated on a primary basis to the aeronautical mobile (R) service, limited to systems operating in accordance with recognised international aeronautical standards. Such use shall be in accordance with Resolution 413 (Rev.WRC-07). The use of the band 108–112 MHz by the aeronautical mobile (R) service shall be limited to systems composed of ground-based transmitters and associated receivers that provide navigational information in support of air navigation functions in accordance with recognised international aeronautical standards. ( ) WRC-07 In the band 117.975–137 MHz, the frequency 121.5 MHz is the aeronautical emergency frequency and, where required, the frequency 123.1 MHz is the aeronautical frequency auxiliary to 121.5 MHz. Mobile stations of the maritime mobile service may communicate on these frequencies under the conditions laid down in Article 31 for distress and safety purposes with stations of the aeronautical mobile service. ( ) WRC-07 Additional allocation: in Armenia, Azerbaijan, Belarus, Bulgaria, Estonia, the Russian Federation, Georgia, Hungary, Iran (Islamic Republic of), Iraq (Republic of), Japan, Kazakhstan, Mali, Mongolia, Mozambique, Uzbekistan, Papua New Guinea, Poland, Kyrgyzstan, Romania, Senegal, Tajikistan, Turkmenistan and Ukraine, the frequency band 132–136 MHz is also allocated to the aeronautical mobile (OR) service on a primary basis. In assigning frequencies to stations of the aeronautical mobile (OR) service, the administration shall take account of the frequencies assigned to stations in the aeronautical mobile (R) service. ( ) WRC-19 Additional allocation: in Saudi Arabia, Armenia, Azerbaijan, Bahrain, Belarus, Bulgaria, the United Arab Emirates, the Russian Federation, Georgia, Iran (Islamic Republic of), Jordan, Mali, Oman, Uzbekistan, Poland, the Syrian Arab Republic, Kyrgyzstan, Romania, Senegal, Tajikistan, Turkmenistan and Ukraine, the frequency band 136–137 MHz is also allocated to the aeronautical mobile (OR) service on a Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('133', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('203C', 'The use of the space operation service (space-to-Earth) with non-geostationary satellite short-duration mission systems in the frequency band 137–138 MHz is subject to Resolution 660 (WRC-19). Resolution 32 (WRC-19) applies. These systems shall not cause harmful interference to, or claim protection from, the existing services to which the frequency band is allocated on a primary basis. ( ) WRC-19 Different category of service: in Afghanistan, Saudi Arabia, Bahrain, Bangladesh, Brunei Darussalam, China, Cuba, the United Arab Emirates, India, Indonesia, Iran (Islamic Republic of), Iraq, Kuwait, Montenegro, Oman, Pakistan, the Philippines, Qatar, Singapore, Thailand and Yemen, the frequency band 137–138 MHz is allocated to the fixed and mobile, except aeronautical mobile (R), services on a primary basis (see No. 33). ( ) WRC-19 Different category of service: in Israel and Jordan, the allocation of the band 137– MHz to the fixed and mobile, except aeronautical mobile, services is on a primary basis (see No. 33). Different category of service: in Armenia, Azerbaijan, Belarus, Bulgaria, Egypt, Finland, France, Georgia, Greece, Kazakhstan, Lebanon, Moldova, Mongolia, Uzbekistan, Poland, Kyrgyzstan, the Syrian Arab Republic, Slovakia, the Czech Rep., Romania, the Russian Federation, Tajikistan, Turkmenistan and Ukraine, the allocation of the band 137–138 MHz to the aeronautical mobile (OR) service is on a primary basis (see No. 33). ( ) WRC-2000 Additional allocation: in Australia, the band 137–144 MHz is also allocated to the broadcasting service on a primary basis until that service can be accommodated within regional broadcasting allocations. The use of the band 137–138 MHz by the mobile–satellite service is subject to coordination under No. 9.11A. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('208A', 'In making assignments to space stations in the mobile–satellite service in the frequency bands 137–138 MHz, 387–390 MHz and 400.15–401 MHz and in the maritime mobile–satellite service (space-to-Earth) in the frequency bands 157.1875–157.3375 MHz and 161.7875–161.9375 MHz, administrations shall take all practicable steps to protect the radio astronomy service in the frequency bands 150.05–153 MHz, 322–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('328', '.6 MHz, 406.1–410 MHz and 608–614 MHz from harmful interference from unwanted emissions as shown in the most recent version of Recommendation ITU-R RA.769. ( ) WRC-19');
