INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('21', '.4–22 GHz, Resolution 739 (Rev.WRC-19) applies. ( ) WRC-19 The use of the bands 137–138 MHz, 148–150.05 MHz, 399.9–400.05 MHz, 400.15– MHz, 454–456 MHz and 459–460 MHz by the mobile–satellite service is limited to non-geostationary-satellite systems. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('209A', 'The use of the frequency band 137.175–137.825 MHz by non-geostationary-satellite systems in the space operation service identified as short-duration missions in accordance with Appendix 4 is not subject to No. 9.11A. ( ) WRC-19 Additional allocation: in Italy, the Czech Rep. and the United Kingdom, the bands');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('138', '–143.6 MHz and 143.65–144 MHz are also allocated to the space research service (space-to-Earth) on a secondary basis. (WRC-07) Additional allocation: in Germany, Saudi Arabia, Austria, Bahrain, Belgium, Denmark, the United Arab Emirates, Spain, Finland, Greece, Guinea, Ireland, Israel, Kenya, Kuwait, Lebanon, Liechtenstein, Luxembourg, North Macedonia, Mali, Malta, Montenegro, Norway, the Netherlands, Qatar, Slovakia, the United Kingdom, Serbia, Slovenia, Somalia, Sweden, Switzerland, Tanzania, Tunisia and Turkey, the frequency band 138–144 MHz is also allocated to the maritime mobile and land mobile services on a primary basis. ( ) WRC-19 Alternative allocation: in Angola, Botswana, Cameroon, the Central African Rep., Congo (Rep. of the), Eswatini, Gabon, Gambia, Ghana, Guinea, Iraq, Jordan, Lesotho, Liberia, Libya, Malawi, Mozambique, Namibia, Niger, Oman, Uganda, Syrian Arab Republic, the Dem. Rep. of the Congo, Rwanda, Sierra Leone, South Africa, Chad, Togo, Zambia and Zimbabwe, the frequency band 138–144 MHz is allocated to the fixed and mobile services on a primary basis. ( ) WRC-19 Additional allocation: in China, the band 138–144 MHz is also allocated to the radiolocation service on a primary basis. Additional allocation: in Eritrea, Ethiopia, Kenya, North Macedonia, Montenegro, Serbia, Somalia, Sudan, South Sudan and Tanzania, the frequency band 138–144 MHz is also allocated to the fixed service on a primary basis. ( ) WRC-19 Additional allocation: in China, the band 144–146 MHz is also allocated to the aeronautical mobile (OR) service on a secondary basis. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('135', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('146', '–148 MHz is allocated to the fixed and mobile services on a primary basis. Additional allocation: the band 148–149.9 MHz is also allocated to the space operation service (Earth-to-space) on a primary basis, subject to agreement obtained under No. 9.21. The bandwidth of any individual transmission shall not exceed ±25 kHz.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('218A', 'The frequency band 148–149.9 MHz in the space operation service (Earth-to-space) may be used by non-geostationary-satellite systems with short-duration missions. Non- geostationary-satellite systems in the space operation service used for short-duration missions in accordance with Resolution 32 (WRC-19) of the Radio Regulations are not subject to agreement under No. 9.21. At the stage of coordination, the provisions of Nos. 9.17 and 9.18 also apply. In the frequency band 148–149.9 MHz, non- geostationary–satellite systems with short-duration missions shall not cause unacceptable interference to, or claim protection from, existing primary services within this frequency band, or impose additional constraints on the space operation and mobile–satellite services. In addition, earth stations in non-geostationary-satellite systems in the space operation service with short-duration missions in the frequency band 148-149.9 MHz shall ensure that the power flux-density does not exceed −149 dB(W/(m2  4 kHz)) for more than 1% of time at the border of the territory of the following countries: Armenia, Azerbaijan, Belarus, China, Korea (Rep. of), Cuba, Russian Federation, India, Iran (Islamic Republic of), Japan, Kazakhstan, Malaysia, Uzbekistan, Kyrgyzstan, Thailand and Viet Nam. In case this power flux-density limit is exceeded, agreement under No. 9.21 is required to be obtained from countries mentioned in this footnote. ( ) WRC-19 The use of the frequency band 148–149.9 MHz by the mobile–satellite service is subject to coordination under No. 9.11A. The mobile–satellite service shall not constrain the development and use of the fixed, mobile and space operation services in the frequency band 148–149.9 MHz. The use of the frequency band 148-149.9 MHz by non-geostationary-satellite systems in the space operation service identified as short- duration mission is not subject to No. 9.11A. ( ) WRC-19 The use of the frequency bands 149.9–150.05 MHz and 399.9–400.05 MHz by the mobile–satellite service is subject to coordination under No. 9.11A. ( ) WRC-15 Stations of the mobile–satellite service in the frequency band 148–149.9 MHz shall not cause harmful interference to, or claim protection from, stations of the fixed or mobile services operating in accordance with the Table of Frequency Allocations in the following countries: Albania, Algeria, Germany, Saudi Arabia, Australia, Austria, Bahrain, Bangladesh, Barbados, Belarus, Belgium, Benin, Bosnia and Herzegovina, Botswana, Brunei Darussalam, Bulgaria, Cameroon, China, Cyprus, Congo (Rep. of the), Korea (Rep. of), Côte d’Ivoire, Croatia, Cuba, Denmark, Djibouti, Egypt, the United Arab Emirates, Eritrea, Spain, Estonia, Eswatini, Ethiopia, the Russian Federation, Finland, France, Gabon, Georgia, Ghana, Greece, Guinea, Guinea Bissau, Hungary, India, Iran (Islamic Republic of), Ireland, Iceland, Israel, Italy, Jamaica, Japan, Jordan, Kazakhstan, Kenya, Kuwait, Lesotho, Latvia, Lebanon, Libya, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('136', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('225A', 'Additional allocation: in Algeria, Armenia, Azerbaijan, Belarus, China, the Russian Federation, France, Iran (Islamic Republic of), Kazakhstan, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan, Ukraine and Viet Nam, the frequency band 154–156 MHz is also allocated to the radiolocation service on a primary basis. The usage of the frequency band 154–156 MHz by the radiolocation service shall be limited to space- object detection systems operating from terrestrial locations. The operation of stations in the radiolocation service in the frequency band 154–156 MHz shall be subject to agreement obtained under No. 9.21. For the identification of potentially affected administrations in Region 1, the instantaneous field-strength value of 12 dB(μV/m) for');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('160', '.6–160.975 MHz and 161.475–162.05 MHz, each administration shall give priority to the maritime mobile service on only such frequencies as are assigned to stations of the maritime mobile service by the administration (see Articles 31 and 52 and Appendix 18). Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('156', '.5625 MHz are also allocated to the fixed and land mobile services on a primary basis. The use of these bands by the fixed and land mobile services shall not cause harmful interference to nor claim protection from the maritime mobile VHF radio communication service. (WRC-07) The use of the frequency bands 156.7625–156.7875 MHz and 156.8125–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228A', 'The frequency bands 161.9625–161.9875 MHz and 162.0125–162.0375 MHz may be used by aircraft stations for the purpose of search and rescue operations and other safety-related communications.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228AA', 'The use of the frequency bands 161.9375–161.9625 MHz and 161.9875–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('162', '.0125 MHz by the maritime mobile–satellite (Earth-to-space) service is limited to the systems which operate in accordance with Appendix 18. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228AB', 'The use of the frequency bands 157.1875–157.3375 MHz and 161.7875–161.9375 MHz by the maritime mobile–satellite service (Earth-to-space) is limited to non- geostationary-satellite systems operating in accordance with Appendix 18. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228AC', 'The use of the frequency bands 157.1875–157.3375 MHz and 161.7875–161.9375 MHz by the maritime mobile–satellite service (space-to-Earth) is limited to non- geostationary-satellite systems operating in accordance with Appendix 18. Such use is subject to agreement obtained under No. 9.21 with respect to the terrestrial services in Azerbaijan, Belarus, China, Korea (Rep. of), Cuba, the Russian Federation, the Syrian Arab Republic, the Dem. People’s Rep. of Korea, South Africa and Viet Nam. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228B', 'The use of the frequency bands 161.9625–161.9875 MHz and 162.0125–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228C', 'The use of the frequency bands 161.9625–161.9875 MHz and 162.0125–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228D', 'The frequency bands 161.9625–161.9875 MHz (AIS 1) and 162.0125–162.0375 MHz (AIS 2) may continue to be used by the fixed and mobile services on a primary basis until 1 January 2025, at which time this allocation shall no longer be valid. Administrations are encouraged to make all practicable efforts to discontinue the use of these bands by the fixed and mobile services prior to the transition date. During this transition period, the maritime mobile service in these frequency bands has priority over the fixed, land mobile and aeronautical mobile services.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228E', 'The use of the automatic identification system in the frequency bands 161.9625–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('228F', 'The use of the frequency bands 161.9625–161.9875 MHz and 162.0125–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('139', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('216', '–225 MHz. Stations authorised prior to 1 January 1990 may continue to operate on a secondary basis. Additional allocation: in Canada and Mexico, the frequency band 216–220 MHz is also allocated to the land mobile service on a primary basis. ( ) WRC-19 Additional allocation: in Somalia, the band 216–225 MHz is also allocated to the aeronautical radionavigation service on a primary basis, subject to not causing harmful interference to existing or planned broadcasting services in other countries. Additional allocation: in Japan, the band 222–223 MHz is also allocated to the aeronautical radionavigation service on a primary basis and to the radiolocation service on a secondary basis. Alternative allocation: in Spain, France, Israel and Monaco, the band 223–230 MHz is allocated to the broadcasting and land mobile services on a primary basis (see No. 33) on the basis that, in the preparation of frequency plans, the broadcasting service shall have prior choice of frequencies; and allocated to the fixed and mobile, except land mobile, services on a secondary basis. However, the stations of the land mobile service shall not cause harmful interference to, or claim protection from, existing or planned broadcasting stations in Morocco and Algeria. Additional allocation: in Saudi Arabia, Bahrain, the United Arab Emirates, Jordan, Oman, Qatar and the Syrian Arab Republic, the band 223–235 MHz is also allocated to the aeronautical radionavigation service on a primary basis. Additional allocation: in China, the band 225–235 MHz is also allocated to the radio astronomy service on a secondary basis. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('140', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('256A', 'Additional allocation: in China, the Russian Federation and Kazakhstan, the frequency band 258–261 MHz is also allocated to the space research service (Earth-to-space) and space operation service (Earth-to-space) on a primary basis. Stations in the space research service (Earth-to-space) and space operation service (Earth-to-space) shall not cause harmful interference to, or claim protection from, or constrain the use and development of, the mobile service systems and mobile–satellite service systems operating in the frequency band. Stations in the space research service (Earth-to-space) and space operation service (Earth-to-space) shall not constrain the future development of fixed service systems of other countries. (WRC-15) The band 267–272 MHz may be used by administrations for space telemetry in their countries on a primary basis, subject to agreement obtained under No. 9.21. The use of the band 328.6–335.4 MHz by the aeronautical radionavigation service is limited to Instrument Landing Systems (glide path). Additional allocation: in Egypt and the Syrian Arab Republic, the band 328.6–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('335', '.4 MHz is also allocated to the mobile service on a secondary basis, subject to agreement obtained under No. 9.21. In order to ensure that harmful interference is not caused to stations of the aeronautical radionavigation service, stations of the mobile service shall not be introduced in the band until it is no longer required for the aeronautical radionavigation service by any administration which may be identified in the application of the procedure invoked under No. 9.21. (WRC-12) Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('141', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('260A', 'In the frequency band 399.9–400.05 MHz, the maximum e.i.r.p. of any emission of earth stations in the mobile–satellite service shall not exceed 5 dBW in any 4 kHz band and the maximum e.i.r.p. of each earth station in the mobile–satellite service shall not exceed 5 dBW in the whole 399.9–400.05 MHz frequency band. Until 22 November');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('202', '2, this limit shall not apply to satellite systems for which complete notification information has been received by the Radiocommunication Bureau by 22 November and that have been brought into use by that date. After 22 November 2022, these limits shall apply to all systems within the mobile–satellite service operating in this frequency band. In the frequency band 399.99–400.02 MHz, the e.i.r.p. limits as specified above shall apply after 22 November 2022 to all systems within the mobile–satellite service. Administrations are requested that their mobile–satellite service satellite links in the');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('399', '.99–400.02 MHz frequency band comply with the e.i.r.p. limits as specified above, after 22 November 2019. (WRC-19)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('260B', 'In the frequency band 400.02-400.05 MHz, the provisions of No. 260A are not applicable for telecommand uplinks within the mobile–satellite service. (WRC-19) Emissions shall be confined in a band of ±25 kHz about the standard frequency');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('264A', 'In the frequency band 401–403 MHz, the maximum e.i.r.p. of any emission of each earth station in the meteorological-satellite service and the Earth exploration-satellite service shall not exceed 22 dBW in any 4 kHz band for geostationary-satellite systems and non-geostationary-satellite systems with an orbit of apogee equal or greater than');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('786', 'km. The maximum e.i.r.p. of any emission of each earth station in the meteorological- satellite service and the Earth exploration-satellite service shall not exceed 7 dBW in any 4 kHz band for non-geostationary-satellite systems with an orbit of apogee lower than 35 786 km. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('142', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('264B', 'Non-geostationary-satellite systems in the meteorological-satellite service and the Earth exploration-satellite service for which complete notification information has been received by the Radiocommunication Bureau before 28 April 2007 are exempt from provisions of No. 264A and may continue to operate in the frequency band 401.898–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('402', '.522 MHz on a primary basis without exceeding a maximum e.i.r.p. level of dBW. (WRC-19) In the frequency band 403–410 MHz, Resolution 205 (Rev.WRC-19) applies. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('143', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('430', '–440 MHz is also allocated to the fixed service on a primary basis. (WRC-19) Different category of service: in Argentina, Brazil, Colombia, Costa Rica, Cuba, Guyana, Honduras, Panama, Paraguay, Uruguay and Venezuela, the allocation of the frequency band 430–440 MHz to the amateur service is on a primary basis (see No. 33). (WRC-19) Additional allocation: in Mexico, the frequency bands 430–435 MHz and 438– MHz are also allocated on a primary basis to the mobile, except aeronautical mobile, service, and on a secondary basis to the fixed service, subject to agreement obtained under No. 9.21. (WRC-19)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('279A', 'The use of the frequency band 432–438 MHz by sensors in the Earth exploration– satellite service (active) shall be in accordance with Recommendation ITU-R RS.1260–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('2', '. Additionally, the Earth exploration–satellite service (active) in the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('432', '–438 MHz shall not cause harmful interference to the aeronautical radionavigation Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('144', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('286A', 'The use of the bands 454–456 MHz and 459–460 MHz by the mobile–satellite service is subject to coordination under No. 9.11A. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('286AA', 'The frequency band 450–470 MHz is identified for use by administrations wishing to implement International Mobile Telecommunications (IMT) — see Resolution 224 (Rev.WRC-19). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. (WRC-19) Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('145', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('286B', 'The use of the band 454–455 MHz in the countries listed in 286D, 455–456 MHz and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('459', '–460 MHz in Region 2, and 454–456 MHz and 459–460 MHz in the countries listed in 286E, by stations in the mobile–satellite service, shall not cause harmful interference to, or claim protection from, stations of the fixed or mobile services operating in accordance with the Table of Frequency Allocations. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('286C', 'The use of the band 454–455 MHz in the countries listed in 286D, 455–456 MHz and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('286D', 'Additional allocation: in Canada, the United States and Panama, the band 454– MHz is also allocated to the mobile–satellite service (Earth-to-space) on a primary basis. ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('286E', 'Additional allocation: in Cape Verde, Nepal and Nigeria, the bands 454–456 MHz and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('457', '.550 MHz, 457.575 MHz and 457.600 MHz paired, respectively, with');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('467', '.750 MHz, 467.775 MHz, 467.800 MHz and 467.825 MHz. The characteristics of the equipment used shall conform to those specified in Recommendation ITU-R M.1174-4. ( ) WRC-19 Earth exploration–satellite service applications, other than the meteorological–satellite service, may also be used in the bands 460–470 MHz and 1 690–1 710 MHz for space- to-Earth transmissions subject to not causing harmful interference to stations operating in accordance with the Table. Different category of service: in Afghanistan, Azerbaijan, Belarus, China, the Russian Federation, Japan, Kyrgyzstan, Tajikistan and Turkmenistan, the allocation of the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('460', '–470 MHz to the meteorological–satellite service (space-to-Earth) is on a primary basis (see No. 33), subject to agreement obtained under No. 9.21. ( ) WRC-12 Additional allocation: in China, the band 470–485 MHz is also allocated to the space research (space-to-Earth) and the space operation (space-to-Earth) services on a primary basis subject to agreement obtained under No. 9.21 and subject to not causing harmful interference to existing and planned broadcasting stations. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('291A', 'Additional allocation: in Germany, Austria, Denmark, Estonia, Liechtenstein, the Czech Rep., Serbia and Switzerland, the frequency band 470–494 MHz is also allocated to the radiolocation service on a secondary basis. This use is limited to the operation of wind profiler radars in accordance with Resolution 217 (WRC-97). ( ) WRC-15 Different category of service: in Argentina, Uruguay and Venezuela, the allocation of the frequency band 470–512 MHz to the mobile service is on a primary basis (see No. 33), subject to agreement obtained under No. 9.21. ( ) WRC-15 Different category of service: in Canada, Chile, Cuba, the United States, Guyana, Jamaica and Panama, the allocation of the frequency bands 470–512 MHz and 614– MHz to the fixed service is on a primary basis (see No. 33), subject to agreement obtained under No. 9.21. In the Bahamas, Barbados, Canada, Chile, Cuba, the United States, Guyana, Jamaica, Mexico and Panama, the allocation of the frequency bands');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('470', '–512 MHz and 614–698 MHz to the mobile service is on a primary basis (see No. 33), subject to agreement obtained under No. 9.21. In Argentina and Ecuador, the allocation of the frequency band 470–512 MHz to the fixed and mobile services is on a primary basis (see No. 33), subject to agreement obtained under No. 9.21. ( ) WRC-15 Additional allocation: in Saudi Arabia, Cameroon, Côte d’Ivoire, Egypt, Ethiopia, Israel, Libya, the Syrian Arab Republic, Chad and Yemen, the frequency band 470– MHz is also allocated to the fixed service on a secondary basis. ( ) WRC-15 In the Bahamas, Barbados, Canada, the United States and Mexico, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('147', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('296A', 'In Micronesia, the Solomon Islands, Tuvalu and Vanuatu, the frequency band 470– MHz, or portions thereof, and in Bangladesh, Maldives and New Zealand, the frequency band 610–698 MHz, or portions thereof, are identified for use by these administrations wishing to implement International Mobile Telecommunications (IMT) – see Resolution 224 (Rev.WRC-19). This identification does not preclude the use of these frequency bands by any application of the services to which they are allocated and does not establish priority in the Radio Regulations. The mobile allocation in this frequency band shall not be used for IMT systems unless subject to agreement obtained under No. 9.21 and shall not cause harmful interference to, or claim protection from, the broadcasting service of neighbouring countries. Nos. 43 and 43A apply. ( ) WRC-19 Additional allocation: in Canada, Costa Rica, Cuba, El Salvador, the United States, Guatemala, Guyana and Jamaica, the frequency band 512–608 MHz is also allocated to the fixed and mobile services on a primary basis, subject to agreement obtained under No. 9.21. In the Bahamas, Barbados and Mexico, the frequency band 512–608 MHz is also allocated to the mobile service on a primary basis, subject to agreement obtained under No. 9.21. In Mexico, the frequency band 512–608 MHz is also allocated on a secondary basis to the fixed service (see No. 32). ( WRC-19) Additional allocation: in India, the band 549.75–550.25 MHz is also allocated to the space operation service (space-to-Earth) on a secondary basis. Additional allocation: in Saudi Arabia, Cameroon, Egypt, United Arab Emirates, Israel, Jordan, Libya, Oman, Qatar, the Syrian Arab Republic and Sudan, the frequency band 582–790 MHz is also allocated to the fixed and mobile, except aeronautical mobile, services on a secondary basis. ( ) WRC-15 Additional allocation: in the African Broadcasting Area (see Nos. 10 to 13), the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('606', '–614 MHz is also allocated to the radio astronomy service on a primary basis. Additional allocation: in China, the band 606–614 MHz is also allocated to the radio astronomy service on a primary basis. Additional allocation: in Region 1, except in the African Broadcasting Area (see Nos. 10 to 13), and in Region 3, the band 608–614 MHz is also allocated to the radio astronomy service on a secondary basis. Additional allocation: in India, the band 608–614 MHz is also allocated to the radio astronomy service on a primary basis. Additional allocation: in Belize, Colombia and Guatemala, the frequency band 614– MHz is also allocated to the mobile service on a primary basis. Stations of the mobile service within the frequency band are subject to agreement obtained under No. 9.21. ( ) WRC-19 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('308A', 'In the Bahamas, Barbados, Belize, Canada, Colombia, the United States, Guatemala and Mexico, the frequency band 614–698 MHz, or portions thereof, is identified for International Mobile Telecommunications (IMT) – see Resolution 224 (Rev.WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('726', '–753 MHz, 778–811 MHz and 822–852 MHz, are also allocated to the aeronautical radionavigation service on a primary basis. (WRC-19)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('312A', 'In Region 1, the use of the frequency band 694–790 MHz by the mobile, except aeronautical mobile, service is subject to the provisions of Resolution 760 (WRC-19). See also Resolution 224 (Rev.WRC-19). ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('313A', 'The frequency band, or portions of the frequency band 698–790 MHz, in Australia, Bangladesh, Brunei Darussalam, Cambodia, China, Korea (Rep. of), Fiji, India, Indonesia, Japan, Kiribati, Lao P.D.R., Malaysia, Myanmar (Union of), New Zealand, Pakistan, Papua New Guinea, the Philippines, the Dem. People’s Rep. of Korea, Solomon Islands, Samoa, Singapore, Thailand, Tonga, Tuvalu, Vanuatu and Viet Nam, are identified for use by these administrations wishing to implement International Mobile Telecommunications (IMT). This identification does not preclude the use of these frequency bands by any application of the services to which they are allocated and does not establish priority in the Radio Regulations. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('316B', 'In Region 1, the allocation to the mobile, except aeronautical mobile, service in the frequency band 790–862 MHz is subject to agreement obtained under No. 9.21 with respect to the aeronautical radionavigation service in countries mentioned in No. 312. For countries party to the GE06 Agreement, the use of stations of the mobile service is also subject to the successful application of the procedures of that Agreement. Resolutions 224 (Rev.WRC-19) and 749 (Rev.WRC-19) shall apply, as appropriate. ( ) WRC-19 Additional allocation: in Region 2 (except Brazil, the United States and Mexico), the frequency band 806–890 MHz is also allocated to the mobile–satellite service on a primary basis, subject to agreement obtained under No. 9.21. The use of this service is intended for operation within national boundaries. ( ) WRC-15 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('149', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('317A', 'The parts of the frequency band 698–960 MHz in Region 2 and the frequency bands');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('694', '–790 MHz in Region 1 and 790–960 MHz in Regions 1 and 3 which are allocated to the mobile service on a primary basis are identified for use by administrations wishing to implement International Mobile Telecommunications (IMT) — see Resolutions 224 (Rev.WRC-19), 760 (Rev.WRC-19) and 749 (Rev.WRC-19), where applicable. This identification does not preclude the use of these frequency bands by any application of the services to which they are allocated and does not establish priority in the Radio Regulations. ( ) WRC-19 Additional allocation: in Canada, the United States and Mexico, the bands 849– MHz and 894–896 MHz are also allocated to the aeronautical mobile service on a primary basis, for public correspondence with aircraft. The use of the band 849– MHz is limited to transmissions from aeronautical stations and the use of the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('894', '–896 MHz is limited to transmissions from aircraft stations. Additional allocation: in Belarus, the Russian Federation and Ukraine, the bands 806– MHz (Earth-to-space) and 856–890 MHz (space-to-Earth) are also allocated to the mobile–satellite, except aeronautical mobile–satellite (R), service. The use of these bands by this service shall not cause harmful interference to, or claim protection from, services in other countries operating in accordance with the Table of Frequency Allocations and is subject to special agreements between the administrations concerned. Additional allocation: in Region 3, the bands 806–890 MHz and 942–960 MHz are also allocated to the mobile–satellite, except aeronautical mobile–satellite (R), service on a primary basis, subject to agreement obtained under No. 9.21. The use of this service is limited to operation within national boundaries. In seeking such agreement, appropriate protection shall be afforded to services operating in accordance with the Table, to ensure that no harmful interference is caused to such services. In Region 1, in the band 862–960 MHz, stations of the broadcasting service shall be operated only in the African Broadcasting Area (see Nos. 10 to 13) excluding Algeria, Burundi, Egypt, Spain, Lesotho, Libya, Morocco, Malawi, Namibia, Nigeria, South Africa, Tanzania, Zimbabwe and Zambia, subject to agreement obtained under No. 9.21. ( ) WRC-12 Additional allocation: in Armenia, Azerbaijan, Belarus, the Russian Federation, Kazakhstan, Uzbekistan, Kyrgyzstan, Tajikistan, Turkmenistan and Ukraine, the frequency band 862–960 MHz, in Bulgaria the frequency bands 862–880 MHz and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('915', '–925 MHz, and in Romania the frequency bands 862–880 MHz and 915–925 MHz, are also allocated to the aeronautical radionavigation service on a primary basis. Such use is subject to agreement obtained under No. 9.21 with administrations concerned and limited to ground-based radiobeacons in operation on 27 October 1997 until the end of their lifetime. ( ) WRC-19 Different category of service: in the United States, the allocation of the band 890– MHz to the radiolocation service is on a primary basis, (see No. 33), subject to agreement obtained under No. 9.21. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('325A', 'Different category of service: in Argentina, Brazil, Costa Rica, Cuba, Dominican Republic, El Salvador, Ecuador, the French overseas departments and communities in Region 2, Guatemala, Paraguay, Uruguay and Venezuela, the frequency band 902– MHz is allocated to the mobile, except aeronautical mobile, service on a primary basis. In Colombia, the frequency band 902–905 MHz is allocated to the land mobile service on a primary basis. ( ) WRC-19 Different category of service: in Chile, the band 903–905 MHz is allocated to the mobile, except aeronautical mobile, service on a primary basis, subject to agreement obtained under No. 9.21. Different category of service: in Australia, the allocation of the band 915–928 MHz to the radiolocation service is on a primary basis (see No. 33).');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('327A', 'The use of the frequency band 960–1 164 MHz by the aeronautical mobile (R) service is limited to systems that operate in accordance with recognised international aeronautical standards. Such use shall be in accordance with Resolution 417 (Rev.WRC-15). ( ) WRC-15 The use of the band 960–1 215 MHz by the aeronautical radionavigation service is reserved on a worldwide basis for the operation and development of airborne electronic aids to air navigation and any directly associated ground-based facilities. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('328A', 'Stations in the radionavigation–satellite service in the band 1 164–1 215 MHz shall operate in accordance with the provisions of Resolution 609 (Rev.WRC-07) and shall not claim protection from stations in the aeronautical radionavigation service in the band 960–1 215 MHz. No. 43A does not apply. The provisions of No. 21.18 shall apply. ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('328AA', 'The frequency band 1 087.7–1 092.3 MHz is also allocated to the aeronautical mobile– satellite (R) service (Earth-to-space) on a primary basis, limited to the space station reception of Automatic Dependent Surveillance-Broadcast (ADS-B) emissions from aircraft transmitters that operate in accordance with recognised international aeronautical standards. Stations operating in the aeronautical mobile–satellite (R) service shall not claim protection from stations operating in the aeronautical radionavigation service. Resolution 425 (WRC-19) shall apply. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('328B', 'The use of the bands 1 164–1 300 MHz, 1 559–1 610 MHz and 5 010–5 030 MHz by systems and networks in the radionavigation–satellite service for which complete coordination or notification information, as appropriate, is received by the Radiocommunication Bureau after 1 January 2005 is subject to the application of the provisions of Nos. 9.12, 9.12A and 9.13. Resolution 610 (WRC-03) shall also apply; however, in the case of radionavigation–satellite service (space-to-space) networks and systems, Resolution 610 (WRC-03) shall only apply to transmitting space stations. In accordance with No. 329A, for systems and networks in the radionavigation–satellite service (space-to-space) in the bands 1 215–1 300 MHz and 1 559–1 610 MHz, the provisions of Nos. 9.7, 9.12, 9.12A and 9.13 shall only apply with respect to other Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('151', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('07', ') Use of the radionavigation–satellite service in the frequency band 1 215–1 300 MHz shall be subject to the condition that no harmful interference is caused to, and no protection is claimed from, the radionavigation service authorized under No. 331. Furthermore, the use of the radionavigation–satellite service in the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('215', '–1 300 MHz shall be subject to the condition that no harmful interference is caused to the radiolocation service. No. 43 shall not apply in respect of the radiolocation service. Resolution 608 (WRC-19) shall apply. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('329A', 'Use of systems in the radionavigation–satellite service (space-to-space) operating in the bands 1 215–1 300 MHz and 1 559–1 610 MHz is not intended to provide safety service applications, and shall not impose any additional constraints on radionavigation–satellite service (space-to-Earth) systems or on other services operating in accordance with the Table of Frequency Allocations. ( ) WRC-07 Additional allocation: in Angola, Saudi Arabia, Bahrain, Bangladesh, Cameroon, China, Djibouti, Egypt, the United Arab Emirates, Eritrea, Ethiopia, Guyana, India, Indonesia, Iran (Islamic Republic of), Iraq, Israel, Japan, Jordan, Kuwait, Nepal, Oman, Pakistan, the Philippines, Qatar, the Syrian Arab Republic, Somalia, Sudan, South Sudan, Chad, Togo and Yemen, the band 1 215–1 300 MHz is also allocated to the fixed and mobile services on a primary basis. (WRC-12) Additional allocation: in Algeria, Germany, Saudi Arabia, Australia, Austria, Bahrain, Belarus, Belgium, Benin, Bosnia and Herzegovina, Brazil, Burkina Faso, Burundi, Cameroon, China, Korea (Rep. of), Croatia, Denmark, Egypt, the United Arab Emirates, Estonia, the Russian Federation, Finland, France, Ghana, Greece, Guinea, Equatorial Guinea, Hungary, India, Indonesia, Iran (Islamic Republic of), Iraq, Ireland, Israel, Jordan, Kenya, Kuwait, Lesotho, Latvia, Lebanon, Liechtenstein, Lithuania, Luxembourg, North Macedonia, Madagascar, Mali, Mauritania, Montenegro, Nigeria, Norway, Oman, Pakistan, the Kingdom of the Netherlands, Poland, Portugal, Qatar, the Syrian Arab Republic, Dem. People’s Rep. of Korea, Slovakia, the United Kingdom, Serbia, Slovenia, Somalia, Sudan, South Sudan, Sri Lanka, South Africa, Sweden, Switzerland, Thailand, Togo, Turkey, Venezuela and Viet Nam, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('152', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('335A', 'In the band 1 260–1 300 MHz, active spaceborne sensors in the Earth exploration– satellite and space research services shall not cause harmful interference to, claim protection from, or otherwise impose constraints on operation or development of the radiolocation service and other services allocated by footnotes on a primary basis. (WRC-2000) The use of the bands 1 300–1 350 MHz, 2 700–2 900 MHz and 9 000–9 200 MHz by the aeronautical radionavigation service is restricted to ground-based radars and to associated airborne transponders which transmit only on frequencies in these bands and only when actuated by radars operating in the same band.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('337A', 'The use of the band 1 300–1 350 MHz by Earth stations in the radionavigation–satellite service and by stations in the radiolocation service shall not cause harmful interference to, nor constrain the operation and development of, the aeronautical-radionavigation service. ( ) WRC-2000 In Kyrgyzstan, Slovakia and Turkmenistan, existing installations of the radionavigation service may continue to operate in the band 1 350–1 400 MHz. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('338A', 'In the frequency bands 1 350–1 400 MHz, 1 427–1 452 MHz, 22.55–23.55 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('52', '.4–52.6 GHz, 81–86 GHz and 92–94 GHz, Resolution 750 (Rev.WRC-19) applies. ( ) WRC-19 The bands 1 370–1 400 MHz, 2 640–2 655 MHz, 4 950–4 990 MHz and 15.20–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('690', '–2 700 MHz, except those provided for by No. 422,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('23', '.6–24 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('31', '.3–31.5 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('48', '.94–49.04 GHz, from airborne stations, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('153', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('50', '.2–50.4 GHz3,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('86', '–92 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('109', '.5–111.8 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('164', '–167 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('182', '–185 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('190', '–191.8 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('226', '–231.5 GHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('250', '–252 GHz. ( ) WRC-03 In the bands 1 400–1 727 MHz, 101–120 GHz and 197–220 GHz, passive research is being conducted by some countries in a programme for the search for intentional emissions of extraterrestrial origin.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('341A', 'In Region 1, the frequency bands 1 427–1 452 MHz and 1 492–1 518 MHz are identified for use by administrations wishing to implement International Mobile Telecommunications (IMT) in accordance with Resolution 223 (Rev.WRC-15). This identification does not preclude the use of these frequency bands by any other applications of the services to which it is allocated and does not establish priority in the Radio Regulations. The use of IMT stations is subject to agreement obtained under No. 9.21 with respect to the aeronautical mobile service used for aeronautical telemetry in accordance with No. 342. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('341B', 'In Region 2, the frequency band 1 427–1 518 MHz is identified for use by administrations wishing to implement International Mobile Telecommunications (IMT) in accordance with Resolution 223 (Rev.WRC-15). This identification does not preclude the use of this frequency band by any application of the services to which they are allocated and does not establish priority in the Radio Regulations. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('341C', 'The frequency bands 1 427–1 452 MHz and 1 492–1 518 MHz are identified for use by administrations in Region 3 wishing to implement International Mobile Telecommunications (IMT) in accordance with Resolution 223 (Rev.WRC-15). The use of these frequency bands by the above administrations for the implementation of IMT in the frequency bands 1 429–1 452 MHz and 1 492–1 518 MHz is subject to agreement obtained under No. 9.21 from countries using stations of the aeronautical mobile service. This identification does not preclude the use of these frequency bands by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('340', '.1 The allocation to the Earth exploration-satellite (passive) and the space research service (passive) in the band 50.2-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('154', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('346A', 'The frequency band 1 452–1 492 MHz is identified for use by administrations in Region 3 wishing to implement International Mobile Telecommunications (IMT) in accordance with Resolution 223 (Rev.WRC-19) and Resolution 761 (WRC-19). The use of this frequency band by the above administrations for the implementation of IMT is subject to agreement obtained under No. 9.21 from countries using stations of the aeronautical mobile service. This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. ( ) WRC-19 The use of the band 1 518–1 525 MHz by the mobile–satellite service is subject to coordination under No. 9.11A. In the band 1 518–1 525 MHz stations in the mobile– The use by Palestine of the allocation to the mobile service in the frequency band 1 452–1 492 MHz identified for IMT is noted, pursuant to Resolution 99 (Rev. Dubai, 2018) and taking into account the Israeli- Palestinian Interim Agreement of 28 September 1995. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('155', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('348A', 'In the band 1 518–1 525 MHz, the coordination threshold in terms of the power flux- density levels at the surface of the Earth in application of No. 9.11A for space stations in the mobile–satellite (space-to-Earth) service, with respect to the land mobile service use for specialised mobile radios or used in conjunction with public switched telecommunication networks (PSTN) operating within the territory of Japan, shall be −150 dB(W/m2) in any 4 kHz band for all angles of arrival, instead of those given in Table 5–2 of Appendix 5. In the band 1 518–1 525 MHz stations in the mobile–satellite service shall not claim protection from stations in the mobile service in the territory of Japan. No. 43A does not apply. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('348B', 'In the band 1 518–1 525 MHz, stations in the mobile–satellite service shall not claim protection from aeronautical mobile telemetry stations in the mobile service in the territory of the United States (see Nos. 343 and 344) and in the countries listed in No. 342. No. 43A does not apply. ( ) WRC-03 Different category of service: in Saudi Arabia, Azerbaijan, Bahrain, Cameroon, Egypt, Iran (Islamic Republic of), Iraq, Israel, Kazakhstan, Kuwait, Lebanon, North Macedonia, Morocco, Qatar, Syrian Arab Republic, Kyrgyzstan, Turkmenistan and Yemen, the allocation of the frequency band 1 525–1 530 MHz to the mobile, except aeronautical mobile, service is on a primary basis (see No. 33). ( ) WRC-19 Additional allocation: in Kyrgyzstan and Turkmenistan, the frequency band 1 525–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('530', 'MHz is also allocated to the aeronautical mobile service on a primary basis. ( ) WRC-19 The bands 1 525–1 544 MHz, 1 545–1 559 MHz, 1 626.5–1 645.5 MHz and 1 646.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('351A', 'For the use of the bands 1 518–1 544 MHz, 1 545–1 559 MHz, 1 610–1 645.5 MHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('646', '.5–1 660.5 MHz, 1 668–1675 MHz, 1 980–2 010 MHz, 2 170–2 200 MHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('483', '.5–2 520 MHz and 2 670–2 690 MHz by the mobile–satellite service, see Resolutions 212 (Rev.WRC-07) and 225 (Rev.WRC-07). ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('352A', 'In the frequency band 1 525–1 530 MHz, stations in the mobile–satellite service, except stations in the maritime mobile–satellite service, shall not cause harmful interference to, or claim protection from, stations of the fixed service in Algeria, Saudi Arabia, Egypt, Guinea, India, Israel, Italy, Jordan, Kuwait, Mali, Morocco, Mauritania, Nigeria, Oman, Pakistan, the Philippines, Qatar, Syrian Arab Republic, Viet Nam and Yemen notified prior to 1 April 1998. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('353A', 'In applying the procedures of Section II of Article 9 to the mobile–satellite service in the bands 1 530–1 544 MHz and 1 626.5–1 645.5 MHz, priority shall be given to Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('12', 'The use of the band 1 544–1 545 MHz by the mobile–satellite service (space-to-Earth) is limited to distress and safety communications (see Article 31). Transmissions in the band 1 545–1 555 MHz from terrestrial aeronautical stations directly to aircraft stations, or between aircraft stations, in the aeronautical mobile (R) service are also authorised when such transmissions are used to extend or supplement the satellite-to-aircraft links.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('357A', 'In applying the procedures of Section II of Article 9 to the mobile–satellite service in the frequency bands 1 545–1 555 MHz and 1 646.5–1 656.5 MHz, priority shall be given to accommodating the spectrum requirements of the aeronautical mobile– satellite (R) service providing transmission of messages with priority 1 to 6 in Article 44. Aeronautical mobile–satellite (R) service communications with priority 1 to 6 in Article 44 shall have priority access and immediate availability, by pre-emption if necessary, over all other mobile-satellite communications operating within a network. Mobile-satellite systems shall not cause unacceptable interference to, or claim protection from, aeronautical mobile-satellite (R) service communications with priority 1 to 6 in Article 44. Account shall be taken of the priority of safety-related communications in the other mobile-satellite services (the provisions of Resolution 222 (WRC-12) shall apply). ( ) WRC-12 Additional allocation: in Germany, Saudi Arabia, Armenia, Azerbaijan, Belarus, Cameroon, the Russian Federation, Georgia, Guinea, Guinea-Bissau, Jordan, Kazakhstan, Kuwait, Lithuania, Mauritania, Uganda, Uzbekistan, Pakistan, Poland, the Syrian Arab Republic, Kyrgyzstan, the Dem. People’s Rep. of Korea, Romania, Tajikistan, Tunisia, Turkmenistan and Ukraine, the frequency bands 1 550–1 559 MHz,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('362A', 'In the United States, in the bands 1 555–1 559 MHz and 1 656.5–1 660.5 MHz, the aeronautical mobile–satellite (R) service shall have priority access and immediate availability, by pre-emption if necessary, over all other mobile–satellite communications operating within a network. Mobile–satellite systems shall not cause unacceptable interference to, or claim protection from, aeronautical mobile– satellite (R) service communications with priority 1 to 6 in Article 44. Account shall be taken of the priority of safety-related communications in the other mobile–satellite services. ( ) WRC-97 The use of the band 1 610–1 626.5 MHz by the mobile–satellite service (Earth-to- space) and by the radiodetermination–satellite service (Earth-to-space) is subject to coordination under No. 9.11A. A mobile Earth station operating in either of the services in this band shall not produce a peak e.i.r.p. density in excess of −15 dB(W/4 kHz) in the part of the band used by systems operating in accordance with the provisions of No. 366 (to which No. 4.10 applies), unless otherwise agreed by the affected administrations. In the part of the band where such systems are not operating, the mean e.i.r.p. density of a mobile Earth station shall not exceed −3 dB(W/4 kHz). Stations of the mobile–satellite service shall not claim protection from stations in the aeronautical radionavigation service, stations operating in accordance with the provisions of No. 366 and stations in the fixed service operating in accordance with the provisions of No. 359. Administrations responsible for the coordination of mobile–satellite networks shall make all practicable efforts to ensure protection of stations operating in accordance with the provisions of No. 366. The use of the band 1 613.8–1 626.5 MHz by the mobile–satellite service (space-to- Earth) is subject to coordination under No. 9.11A. The band 1 610–1 626.5 MHz is reserved on a worldwide basis for the use and development of airborne electronic aids to air navigation and any directly associated ground-based or satellite-borne facilities. Such satellite use is subject to agreement obtained under No. 9.21. Additional allocation: The frequency band 1 610–1 626.5 MHz is also allocated to the aeronautical mobile–satellite (R) service on a primary basis, subject to agreement obtained under No. 9.21. The provisions of No. 4.10 do not apply with respect to the radiodetermination–satellite and mobile–satellite services in the frequency band 1 610–1 626.5 MHz. However, No.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('4', '.10 applies in the frequency band 1 610–1 626.5 MHz with respect to the aeronautical radionavigation–satellite service when operating in accordance with No. 366, the aeronautical mobile–satellite (R) service when operating in accordance with No. 367, and in the frequency band 1 621.35–1 626.5 MHz with respect to the maritime mobile– satellite service when used for GMDSS. ( ) WRC-19 Different category of service: in Angola, Australia, China, Eritrea, Ethiopia, India, Iran (Islamic Republic of), Israel, Lebanon, Liberia, Madagascar, Mali, Pakistan, Papua New Guinea, Syrian Arab Republic, the Dem. Rep. of the Congo, Sudan, South Sudan, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('158', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('626', '.5–1 660.5 MHz, unless otherwise agreed between the notifying administrations. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('373A', 'Maritime mobile earth stations receiving in the frequency band 1 621.35–1 626.5 MHz shall not impose constraints on the assignments of earth stations of the mobile–satellite service (Earth-to-space) and the radiodetermination–satellite service (Earth-to-space) in the frequency band 1 621.35–1 626.5 MHz in networks for which complete coordination information has been received by the Radiocommunication Bureau before October 2019. ( ) WRC-19 Mobile Earth stations in the mobile–satellite service operating in the bands 1 631.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('634', '.5 MHz and 1 656.5–1 660 MHz shall not cause harmful interference to stations in the fixed service operating in the countries listed in No. 359. ( ) WRC-97 The use of the band 1 645.5–1 646.5 MHz by the mobile–satellite service (Earth-to- space) and for inter–satellite links is limited to distress and safety communications (see Article 31). Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('159', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('376A', 'Mobile Earth stations operating in the band 1 660.0–1 660.5 MHz shall not cause harmful interference to stations in the radio astronomy service. ( ) WRC-97 Additional allocation: in Bangladesh, India, Indonesia, Nigeria and Pakistan, the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('379A', 'Administrations are urged to give all practicable protection in the band 1 660.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('668', '.4 MHz for future research in radio astronomy, particularly by eliminating air-to- ground transmissions in the meteorological aids service in the band 1 664.4–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('379B', 'The use of the band 1 668–1 675 MHz by the mobile–satellite service is subject to coordination under No. 9.11A. In the band 1 668–1 668.4 MHz, Resolution 904 (WRC-07) shall apply. (WRC-07)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('379C', 'In order to protect the radio astronomy service in the band 1 668–1 670 MHz, the aggregate power flux-density values produced by mobile Earth stations in a network of the mobile–satellite service operating in this band shall not exceed −181 dB(W/m2) in MHz and −194 dB(W/m2) in any 20 kHz at any radio astronomy station recorded in the Master International Frequency Register, for more than 2% of integration periods of 2 000 s. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('379D', 'For sharing of the band 1 668.4–1 675 MHz between the mobile–satellite service and the fixed and mobile services, Resolution 744 (Rev.WRC-07) shall apply. ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('379E', 'In the band 1 668.4–1 675 MHz, stations in the mobile–satellite service shall not cause harmful interference to stations in the meteorological aids service in China, Iran (Islamic Republic of), Japan and Uzbekistan. In the band 1 668.4–1 675 MHz, administrations are urged not to implement new systems in the meteorological aids service and are encouraged to migrate existing meteorological aids service operations to other bands as soon as practicable. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('380A', 'In the band 1 670–1 675 MHz, stations in the mobile–satellite service shall not cause harmful interference to, nor constrain the development of, existing earth stations in the meteorological–satellite service notified before 1 January 2004. Any new assignment to these earth stations in this band shall also be protected from harmful interference from stations in the mobile–satellite service. ( ) WRC-07 Additional allocation: in Afghanistan, Cuba, India, Iran (Islamic Republic of) and Pakistan, the band 1 690–1 700 MHz is also allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-12 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('97', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('384A', 'The frequency bands 1 710–1 885 MHz, 2 300–2 400 MHz and 2 500–2 690 MHz, or portions thereof, are identified for use by administrations wishing to implement International Mobile Telecommunications (IMT) in accordance with Resolution 223 (Rev.WRC-15). This identification does not preclude the use of these frequency bands by any application of the services to which they are allocated and does not establish priority in the Radio Regulations. ( ) WRC-15 Additional allocation: the band 1 718.8–1 722.2 MHz is also allocated to the radio astronomy service on a secondary basis for spectral line observations. (WRC-2000) Additional allocation: the frequency band 1 750–1 850 MHz is also allocated to the space operation (Earth-to-space) and space research (Earth-to-space) services in Region 2 (except in Mexico), in Australia, Guam, India, Indonesia and Japan on a primary basis, subject to agreement obtained under No. 9.21, having particular regard to troposcatter systems. ( ) WRC-15 Additional allocation: in Belarus, Georgia, Kazakhstan, Kyrgyzstan, Romania, Tajikistan and Turkmenistan, the band 1 770–1 790 MHz is also allocated to the meteorological–satellite service on a primary basis, subject to agreement obtained under No. 9.21. ( ) WRC-12 The frequency bands 1 885–2 025 MHz and 2 110–2 200 MHz are intended for use, on a worldwide basis, by administrations wishing to implement International Mobile Telecommunications (IMT). Such use does not preclude the use of these frequency bands by other services to which they are allocated. The frequency bands should be made available for IMT in accordance with Resolution 212 (Rev.WRC-15) (see also Resolution 223 (Rev.WRC-15)). ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('388A', 'In Regions 1 and 3, the bands 1 885–1 980 MHz, 2 010–2 025 MHz and 2 110–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('170', 'MHz and, in Region 2, the bands 1 885–1 980 MHz and 2 110–2 160 MHz may be used by high altitude platform stations as base stations to provide International Mobile Telecommunications–2000 (IMT–2000), in accordance with Resolution 221 (Rev.WRC-03). Their use by IMT–2000 applications using high altitude platform Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('388B', 'In Algeria, Saudi Arabia, Bahrain, Benin, Burkina Faso, Cameroon, Comoros, Côte d’Ivoire, China, Cuba, Djibouti, Egypt, United Arab Emirates, Eritrea, Ethiopia, Gabon, Ghana, India, Iran (Islamic Republic of), Israel, Jordan, Kenya, Kuwait, Lebanon, Libya, Mali, Morocco, Mauritania, Nigeria, Oman, Uganda, Pakistan, Qatar, the Syrian Arab Republic, Senegal, Singapore, Sudan, South Sudan, Tanzania, Chad, Togo, Tunisia, Yemen, Zambia and Zimbabwe, for the purpose of protecting fixed and mobile services, including IMT mobile stations, in their territories from co-channel interference, a high altitude platform station (HAPS) operating as an IMT base station in neighbouring countries, in the frequency bands referred to in No. 388A, shall not exceed a co-channel power flux-density of −127 dB(W/(m2·MHz)) at the Earth’s surface outside a country’s borders unless explicit agreement of the affected administration is provided at the time of the notification of HAPS. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('389A', 'The use of the bands 1 980–2 010 MHz and 2 170–2 200 MHz by the mobile–satellite service is subject to coordination under No. 9.11A and to the provisions of Resolution 716 (Rev.WRC-2000). ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('389B', 'The use of the frequency band 1 980–1 990 MHz by the mobile–satellite service shall not cause harmful interference to or constrain the development of the fixed and mobile services in Argentina, Brazil, Canada, Chile, Ecuador, the United States, Honduras, Jamaica, Mexico, Paraguay, Peru, Suriname, Trinidad and Tobago, Uruguay and Venezuela. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('389C', 'The use of the bands 2 010–2 025 MHz and 2 160–2 170 MHz in Region 2 by the mobile–satellite service is subject to coordination under No. 9.11A and to the provisions of Resolution 716 (Rev.WRC-2000). ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('389E', 'The use of the bands 2 010–2 025 MHz and 2 160–2 170 MHz by the mobile–satellite service in Region 2 shall not cause harmful interference to, or constrain the development of, the fixed and mobile services in Regions 1 and 3.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('389F', 'In Algeria, Cape Verde, Egypt, Iran (Islamic Republic of), Mali, the Syrian Arab Republic and Tunisia, the use of the frequency bands 1 980–2 010 MHz and 2 170–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('110', 'MHz and 2 200–2 290 MHz, shall not impose any constraints on Earth-to-space, space-to-Earth and other space-to-space transmissions of those services and in those bands between geostationary and non-geostationary satellites. Additional allocation: in Canada, the United States and India, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('310', '–2 360 MHz is also allocated to the broadcasting–satellite service (sound) and complementary terrestrial sound broadcasting service on a primary basis. Such use is limited to digital audio broadcasting and is subject to the provisions of Resolution 528 (Rev.WRC-19), with the exception of resolves 3 in regard to the limitation on broadcasting–satellite systems in the upper 25 MHz. Complementary terrestrial sound broadcasting stations shall be subject to bilateral coordination with neighbouring countries prior to their bringing into use. ( ) WRC-19 In the United States, the use of the band 2 300–2 390 MHz by the aeronautical mobile service for telemetry has priority over other uses by the mobile services. In Canada, the use of the band 2 360–2 400 MHz by the aeronautical mobile service for telemetry has priority over other uses by the mobile services. ( ) WRC-07 In France and Turkey, the use of the band 2 310–2 360 MHz by the aeronautical mobile service for telemetry has priority over other uses by the mobile service. ( ) WRC-03 In respect of the radiodetermination–satellite service in the band 2 483.5–2 500 MHz, the provisions of No. 4.10 do not apply.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('398A', 'Different category of service: In Armenia, Azerbaijan, Belarus, the Russian Federation, Kazakhstan, Uzbekistan, Kyrgyzstan, Tajikistan and Ukraine, the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('500', 'MHz. ( ) WRC-12 Except for cases referred to in No. 118B, stations of the radiodetermination–satellite service operating in the frequency band 2 483.5–2 500 MHz for which notification information is received by the Bureau after 17 February 2012, and the service area of which includes Armenia, Azerbaijan, Belarus, the Russian Federation, Kazakhstan, Uzbekistan, Kyrgyzstan, Tajikistan and Ukraine, shall not cause harmful interference to, and shall not claim protection from stations of the radiolocation service operating in these countries in accordance with No. 118A. ( ) WRC-12 In Angola, Australia, Bangladesh, China, Eritrea, Eswatini, Ethiopia, India, Lebanon, Liberia, Libya, Madagascar, Mali, Pakistan, Papua New Guinea, Syrian Arab Republic, Dem. Rep. of the Congo, Sudan, Togo and Zambia, the frequency band 2 483.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('163', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('516', '.5 MHz may also be used for the radiodetermination–satellite service (space-to- Earth) for operation limited to within national boundaries, subject to agreement obtained under No. 9.21. In the band 2 500–2 520 MHz, the power flux-density at the surface of the Earth from space stations operating in the mobile–satellite (space-to-Earth) service shall not exceed −152 dB(W/m2/4 kHz) in Argentina, unless otherwise agreed by the administrations concerned. The band 2 500–2 690 MHz may be used for tropospheric scatter systems in Region 1, subject to agreement obtained under No. 9.21. No. 9.21 does not apply to tropospheric scatter links situated entirely outside Region 1. Administrations shall make all practicable efforts to avoid developing new tropospheric scatter systems in this band. When planning new tropospheric scatter radio-relay links in this band, all possible measures shall be taken to avoid directing the antennas of these links towards the geostationary-satellite orbit. ( ) WRC-12 Alternative allocation: in Kyrgyzstan and Turkmenistan, the band 2 500–2 690 MHz is allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. ( ) WRC-12 In the design of systems in the broadcasting–satellite service in the bands between');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('414A', 'In Japan and India, the use of the bands 2 500–2 520 MHz and 2 520–2 535 MHz, under No. 403, by a satellite network in the mobile–satellite service (space-to-Earth) is limited to operation within national boundaries and subject to the application of No. 9.11A. The following pfd values shall be used as a threshold for coordination under No. 9.11A, for all conditions and for all methods of modulation, in an area of 1 000 km around the territory of the administration notifying the mobile–satellite service network: −136 dB(W/(m2·MHz)) for 0 ≤  ≤ 5 −136 + 0.55 ( − 5)dB(W/(m2·MHz)) for 5 <  ≤ 25 −125 dB(W/(m2·MHz)) for 25 <  ≤ 90 where  is the angle of arrival of the incident wave above the horizontal plane, in degrees. Outside this area Table 21–4 of Article 21 shall apply. Furthermore, the coordination thresholds in Table 5–2 of Annex 1 to Appendix 5 of the Radio Regulations (Edition of 2004), in conjunction with the applicable provisions of Articles 9 and 11 associated with No. 9.11A, shall apply to systems for which complete notification information has been received by the Radiocommunication Bureau by November 2007 and that have been brought into use by that date. (WRC-07) The use of the bands 2 500–2 690 MHz in Region 2 and 2 500–2 535 MHz and 2 655–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('415A', 'Additional allocation: in India and Japan, subject to agreement obtained under No. 9.21, the band 2 515–2 535 MHz may also be used for the aeronautical mobile– satellite service (space-to-Earth) for operation limited to within their national boundaries. ( ) WRC-2000 The use of the band 2 520–2 670 MHz by the broadcasting–satellite service is limited to national and regional systems for community reception, subject to agreement obtained under No. 9.21. The provisions of No. 9.19 shall be applied by administrations in this band in their bilateral and multilateral negotiations. ( ) WRC-07 Additional allocation: in India, the frequency band 2 535–2 655 MHz is also allocated to the broadcasting–satellite service (sound) and complementary terrestrial broadcasting service on a primary basis. Such use is limited to digital audio broadcasting and is subject to the provisions of Resolution 528 (Rev.WRC-19). The provisions of No. 416 and Table 21–4 of Article 21, do not apply to this additional allocation. Use of non-geostationary-satellite systems in the broadcasting–satellite service (sound) is subject to Resolution 539 (Rev.WRC-19). Geostationary broadcasting–satellite service (sound) systems for which complete Appendix 4 coordination information has been received after 1 June 2005 are limited to systems intended for national coverage. The power flux-density at the Earth’s surface produced by emissions from a geostationary broadcasting–satellite service (sound) space station operating in the frequency band 2 630–2 655 MHz, and for which complete Appendix 4 coordination information has been received after 1 June 2005, shall not exceed the following limits, for all conditions and for all methods of modulation: Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('165', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('418A', 'In certain Region 3 countries listed in No. 418, use of the band 2 630–2 655 MHz by non-geostationary-satellite systems in the broadcasting–satellite service (sound) for which complete Appendix 4 coordination information, or notification information, has been received after 2 June 2000, is subject to the application of the provisions of No. 9.12A, in respect of geostationary-satellite networks for which complete Appendix 4 coordination information, or notification information, is considered to have been received after 2 June 2000, and No. 22.2 does not apply. No. 22.2 shall continue to apply with respect to geostationary-satellite networks for which complete Appendix 4 coordination information, or notification information, is considered to have been received before 3 June 2000. (WRC-03)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('418B', 'Use of the band 2 630–2 655 MHz by non-geostationary-satellite systems in the broadcasting–satellite service (sound), pursuant to No. 418, for which complete Appendix 4 coordination information, or notification information, has been received after 2 June 2000, is subject to the application of the provisions of No. 9.12. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('03', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('418C', 'Use of the band 2 630–2 655 MHz by geostationary-satellite networks for which complete Appendix 4 coordination information, or notification information, has been received after 2 June 2000 is subject to the application of the provisions of No. 9.13 with respect to non-geostationary-satellite systems in the broadcasting-satellite service (sound), pursuant to No. 418 and No. 22.2 does not apply. ( ) WRC-03 When introducing systems of the mobile–satellite service in the band 2 670–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('166', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('424A', 'In the band 2 900–3 100 MHz, stations in the radiolocation service shall not cause harmful interference to, nor claim protection from, radar systems in the radionavigation service. ( ) WRC-03 In the band 2 900–3 100 MHz, the use of the shipborne interrogator-transponder (SIT) system shall be confined to the sub-band 2 930–2 950 MHz. The use of the band 2 900–3 100 MHz by the aeronautical radionavigation service is limited to ground-based radars. In the bands 2 900–3 100 MHz and 9 300–9 500 MHz, the response from radar transponders shall not be capable of being confused with the response from radar beacons (racons) and shall not cause interference to ship or aeronautical radars in the radionavigation service, having regard, however, to No. 4.9. Additional allocation: in Kyrgyzstan and Turkmenistan, the frequency band 3 100–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('300', 'MHz is also allocated to the radionavigation service on a primary basis. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('429A', 'Additional allocation: in Angola, Benin, Botswana, Burkina Faso, Burundi, Djibouti, Eswatini, Ghana, Guinea, Guinea-Bissau, Lesotho, Liberia, Malawi, Mauritania, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('167', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('429B', 'In the following countries of Region 1 south of 30° parallel north: Angola, Benin, Botswana, Burkina Faso, Burundi, Cameroon, Congo (Rep. of the), Côte d’Ivoire, Egypt, Eswatini, Ghana, Guinea, Guinea-Bissau, Kenya, Lesotho, Liberia, Malawi, Mauritania, Mozambique, Namibia, Niger, Nigeria, Uganda, the Dem. Rep. of the Congo, Rwanda, Sudan, South Sudan, South Africa, Tanzania, Chad, Togo, Zambia and Zimbabwe, the frequency band 3 300–3 400 MHz is identified for the implementation of International Mobile Telecommunications (IMT). The use of this frequency band shall be in accordance with Resolution 223 (Rev.WRC-19). The use of the frequency band 3 300–3 400 MHz by IMT stations in the mobile service shall not cause harmful interference to, or claim protection from, systems in the radiolocation service, and administrations wishing to implement IMT shall obtain the agreement of neighbouring countries to protect operations within the radiolocation service. This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('429C', 'Different category of service: in Argentina, Belize, Brazil, Chile, Colombia, Costa Rica, the Dominican Republic, El Salvador, Ecuador, Guatemala, Mexico, Paraguay and Uruguay, the frequency band 3 300–3 400 MHz is allocated to the mobile, except aeronautical mobile, service on a primary basis. In Argentina, Brazil, the Dominican Republic, Guatemala, Mexico, Paraguay and Uruguay, the frequency band 3 300–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('429D', 'In the following counties in Region 2: Argentina, Belize, Brazil, Chile, Colombia, Costa Rica, the Dominican Republic, El Salvador, Ecuador, Guatemala, Mexico, Paraguay and Uruguay, the use of the frequency band 3 300–3 400 MHz is identified for the implementation of International Mobile Telecommunications (IMT). Such use shall be in accordance with Resolution 223 (Rev.WRC-19). This use in Argentina, Paraguay and Uruguay is subject to the application of No. 9.21. The use of the frequency band 3 300–3 400 MHz by IMT stations in the mobile service shall not cause harmful interference to, or claim protection from, systems in the radiolocation service, and administrations wishing to implement IMT shall obtain the agreement of neighbouring countries to protect operations within the radiolocation service. This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. ( ) WRC-19 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('429E', 'Additional allocation: in Papua New Guinea, the frequency band 3 300–3 400 MHz is allocated to the mobile, except aeronautical mobile, service on a primary basis. Stations in the mobile service operating in the frequency band 3 300–3 400 MHz shall not cause harmful interference to, or claim protection from, stations operating in the radiolocation service. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('429F', 'In the following countries in Region 3: Cambodia, India, Indonesia, Lao P.D.R., Pakistan, the Philippines and Viet Nam, the use of the frequency band 3 300–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('430A', 'The allocation of the frequency band 3 400–3 600 MHz to the mobile, except aeronautical mobile, service is subject to agreement obtained under No. 9.21. This frequency band is identified for International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. The provisions of Nos. 9.17 and 9.18 shall also apply in the coordination phase. Before an administration brings into use a (base or mobile) station of the mobile service in this frequency band, it shall ensure that the power flux-density (pfd) produced at 3 m above ground does not exceed −154.5 dB(W/(m2·4 kHz)) for more than 20% of time at the border of the territory of any other administration. This limit may be exceeded on the territory of any country whose administration has so agreed. In order to ensure that the pfd limit at the border of the territory of any other administration is met, the calculations and verification shall be made, taking into account all relevant information, with the mutual agreement of both administrations (the administration responsible for the terrestrial station and the administration responsible for the earth station), with the assistance of the Bureau if so requested. In case of disagreement, calculation and verification of the pfd shall be made by the Bureau, taking into account the information referred to above. Stations of the mobile service in the frequency band 3 400–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('169', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('431A', 'In Region 2, the allocation of the frequency band 3 400–3 500 MHz to the mobile, except aeronautical mobile, service on a primary basis is subject to agreement obtained under No. 9.21. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('431B', 'In Region 2, the frequency band 3 400–3 600 MHz is identified for use by administrations wishing to implement International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. At the stage of coordination the provisions of Nos. 9.17 and 9.18 also apply. Before an administration brings into use a base or mobile station of an IMT system, it shall seek agreement under No. 9.21 with other administrations and ensure that the power flux-density (pfd) produced at 3 m above ground does not exceed −154.5 dB(W/(m2·4 kHz)) for more than 20% of time at the border of the territory of any other administration. This limit may be exceeded on the territory of any country whose administration has so agreed. In order to ensure that the pfd limit at the border of the territory of any other administration is met, the calculations and verification shall be made, taking into account all relevant information, with the mutual agreement of both administrations (the administration responsible for the terrestrial station and the administration responsible for the earth station), with the assistance of the Bureau if so requested. In case of disagreement, the calculation and verification of the pfd shall be made by the Bureau, taking into account the information referred to above. Stations of the mobile service, including IMT systems, in the frequency band 3 400–3 600 MHz shall not claim more protection from space stations than that provided in Table 21-4 of the Radio Regulations (Edition of 2004). ( ) WRC-15 Different category of service: in Korea (Rep. of), Japan, Pakistan and the Dem. People’s Rep. of Korea, the allocation of the frequency band 3 400–3 500 MHz to the mobile, except aeronautical mobile, service is on a primary basis (see No. 33). ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('432A', 'In Korea (Rep. of), Japan, Pakistan and the Dem. People’s Rep. of Korea, the frequency band 3 400–3 500 MHz is identified for International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. At the stage of coordination the provisions of Nos. 9.17 and 9.18 also apply. Before an administration brings into use a (base or mobile) station of the mobile service in this frequency band it shall ensure that the power flux-density (pfd) produced at 3 m above ground does not exceed −154.5 dB(W/(m2·4 kHz)) for more than 20% of time at the border of the territory of any other administration. This limit may be exceeded on the territory of any country whose administration has so agreed. In order to ensure that the pfd limit at the border of the territory of any other administration is met, the calculations and verification shall be made, taking into account all relevant information, with the mutual agreement of both administrations (the administration responsible for the terrestrial station and the administration responsible for the earth station), with the assistance of the Bureau if so requested. In case of disagreement, the calculation and verification of the pfd shall be made by the Bureau, taking into account the information referred to above. Stations of the mobile service in the frequency band 3 400–3 500 MHz shall not claim more protection from Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('432B', 'Different category of service: in Australia, Bangladesh, Brunei Darussalam, China, French overseas communities of Region 3, India, Indonesia, Iran (Islamic Republic of), Malaysia, New Zealand, the Philippines, Singapore and Thailand, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('433A', 'In Australia, Bangladesh, Brunei Darussalam, China, French overseas communities of Region 3, Korea (Rep. of), India, Indonesia, Iran (Islamic Republic of), Japan, New Zealand, Pakistan, the Philippines and the Dem. People’s Rep. of Korea, the frequency band 3 500–3 600 MHz is identified for International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. At the stage of coordination the provisions of Nos. 9.17 and 9.18 also apply. Before an administration brings into use a (base or mobile) station of the mobile service in this frequency band it shall ensure that the power flux-density (pfd) produced at 3 m above ground does not exceed −154.5 dB(W/(m2·4 kHz)) for more than 20% of time at the border of the territory of any other administration. This limit may be exceeded on the territory of any country whose administration has so agreed. In order to ensure that the pfd limit at the border of the territory of any other administration is met, the calculations and verification shall be made, taking into account all relevant information, with the mutual agreement of both administrations Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('171', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('172', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('440A', 'In Region 2 (except Brazil, Cuba, French Overseas Departments and Communities, Guatemala, Paraguay, Uruguay and Venezuela), and in Australia, the band 4 400–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('940', 'MHz may be used for aeronautical mobile telemetry for flight testing by aircraft stations (see No. 1.83). Such use shall be in accordance with Resolution 416 (WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('11', '.45 GHz (space-to-Earth) and 12.75–13.25 GHz (Earth-to-space) by geostationary- satellite systems in the fixed–satellite service shall be in accordance with the provisions of Appendix 30B. The use of the bands 10.7–10.95 GHz (space-to-Earth), 11.2–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('441A', 'In Brazil, Paraguay and Uruguay, the frequency band 4 800–4 900 MHz, or portions thereof, is identified for the implementation of International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. The use of this frequency band for the implementation of IMT is subject to agreement obtained with neighbouring countries, and IMT stations shall not claim protection from stations of other applications of the mobile service. Such use shall be in accordance with Resolution 223 (Rev.WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('441B', 'In Angola, Armenia, Azerbaijan, Benin, Botswana, Brazil, Burkina Faso, Burundi, Cambodia, Cameroon, China, Côte d’Ivoire, Djibouti, Eswatini, Russian Federation, Gambia, Guinea, Iran (Islamic Republic of), Kazakhstan, Kenya, Lao P.D.R., Lesotho, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('173', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('990', 'MHz, or portions thereof, is identified for use by administrations wishing to implement International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. The use of IMT stations is subject to agreement obtained under No. 9.21 with concerned administrations, and IMT stations shall not claim protection from stations of other applications of the mobile service. In addition, before an administration brings into use an IMT station in the mobile service, it shall ensure that the power flux-density (pfd) produced by this station does not exceed −155 dB(W/m2·1 MHz)) produced up to km above sea level at 20 km from the coast, defined as the low-water mark, as officially recognised by the coastal State. This pfd criterion is subject to review at WRC-23. Resolution 223 (Rev.WRC-19) applies. This identification shall be effective after WRC-19. ( ) WRC-19 In the frequency bands 4 825–4 835 MHz and 4 950–4 990 MHz, the allocation to the mobile service is restricted to the mobile, except aeronautical mobile, service. In Region 2 (except Brazil, Cuba, Guatemala, Mexico, Paraguay, Uruguay and Venezuela), and in Australia, the frequency band 4 825–4 835 MHz is also allocated to the aeronautical mobile service, limited to aeronautical mobile telemetry for flight testing by aircraft stations. Such use shall be in accordance with Resolution 416 (WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('443AA', 'In the frequency bands 5 000–5 030 MHz and 5 091–5 150 MHz, the aeronautical mobile–satellite (R) service is subject to agreement obtained under No. 9.21. The use of these bands by the aeronautical mobile–satellite (R) service is limited to internationally standardized aeronautical systems.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('443B', 'In order not to cause harmful interference to the microwave landing system operating above 5 030 MHz, the aggregate power flux-density produced at the Earth’s surface in the frequency band 5 030–5 150 MHz by all the space stations within any radionavigation–satellite service system (space-to-Earth) operating in the frequency band 5 010–5 030 MHz shall not exceed −124.5 dB(W/m2) in a 150 kHz band. In order not to cause harmful interference to the radio astronomy service in the band 4 990–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('030', 'MHz shall comply with the limits in the frequency band 4 990–5 000 MHz defined in Resolution 741 (Rev.WRC-15). ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('443C', 'The use of the frequency band 5 030–5 091 MHz by the aeronautical mobile (R) service is limited to internationally standardized aeronautical systems. Unwanted emissions from the aeronautical mobile (R) service in the frequency band 5 030–5 091 MHz shall be limited to protect RNSS system downlinks in the adjacent 5 010–5 030 MHz band. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('174', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('010', '–5 030 MHz for any AM(R)S station unwanted emission should be used. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('443D', 'In the frequency band 5 030–5 091 MHz, the aeronautical mobile–satellite (R) service is subject to coordination under No. 9.11A. The use of this frequency band by the aeronautical mobile–satellite (R) service is limited to internationally standardized aeronautical systems. The frequency band 5 030–5 150 MHz is to be used for the operation of the international standard system (microwave landing system) for precision approach and landing. In the frequency band 5 030–5 091 MHz, the requirements of this system shall have priority over other uses of this frequency band. For the use of the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('091', '–5 150 MHz, No. 444A and Resolution 114 (Rev.WRC-15) apply. (WRC-15)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('444A', 'The use of the allocation to the fixed–satellite service (Earth-to-space) in the frequency band 5 091–5 150 MHz is limited to feeder links of non-geostationary-satellite systems in the mobile–satellite service and is subject to coordination under No. 9.11A. The use of the frequency band 5 091–5 150 MHz by feeder links of non-geostationary satellite systems in the mobile–satellite service shall be subject to application of Resolution 114 (Rev.WRC-15). Moreover, to ensure that the aeronautical radionavigation service is protected from harmful interference, coordination is required for feeder-link earth stations of the non-geostationary satellite systems in the mobile-satellite service which are separated by less than 450 km from the territory of an administration operating ground stations in the aeronautical radionavigation service. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('444B', 'The use of the frequency band 5 091–5 150 MHz by the aeronautical mobile service is limited to: • systems operating in the aeronautical mobile (R) service and in accordance with international aeronautical standards, limited to surface applications at airports. Such use shall be in accordance with Resolution 748 (Rev.WRC-19); • aeronautical telemetry transmissions from aircraft stations (see No. 1.83) in accordance with Resolution 418 (Rev.WRC-19). ( ) WRC-19 Additional allocation: in the countries listed in No. 369, the band 5 150–5 216 MHz is also allocated to the radiodetermination–satellite service (space-to-Earth) on a primary basis, subject to agreement obtained under No. 9.21. In Region 2 (except in Mexico), the frequency band is also allocated to the radiodetermination–satellite service (space- to-Earth) on a primary basis. In Regions 1 and 3, except those countries listed in No. 369 and Bangladesh, the frequency band is also allocated to the radiodetermination–satellite service (space-to-Earth) on a secondary basis. The use by the radiodetermination–satellite service is limited to feeder links in conjunction with the radiodetermination–satellite service operating in the frequency bands 1 610–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('175', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('446A', 'The use of the frequency bands 5 150–5 350 MHz and 5 470–5 725 MHz by the stations in the mobile, except aeronautical mobile, service shall be in accordance with Resolution 229 (Rev.WRC-19). ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('446B', 'In the band 5 150–5 250 MHz, stations in the mobile service shall not claim protection from Earth stations in the fixed–satellite service. No. 43A does not apply to the mobile service with respect to fixed–satellite service Earth stations. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('446C', 'Additional allocation: in Region 1 (except in Algeria, Saudi Arabia, Bahrain, Egypt, United Arab Emirates, Iraq, Jordan, Kuwait, Lebanon, Morocco, Oman, Qatar, Syrian Arab Republic, Sudan, South Sudan and Tunisia), the frequency band 5 150–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('446D', 'Additional allocation: in Brazil, the band 5 150–5 250 MHz is also allocated to the aeronautical mobile service on a primary basis, limited to aeronautical telemetry transmissions from aircraft stations (see No. 1.83), in accordance with Resolution 418 (Rev.WRC-19). ( ) WRC-19 Additional allocation: in Côte d''Ivoire, Egypt, Lebanon, the Syrian Arab Republic and Tunisia, the frequency band 5 150–5 250 MHz is also allocated to the mobile service, on a primary basis, subject to agreement obtained under No. 9.21. In this case, the provisions of Resolution 229 (Rev.WRC-19) do not apply. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('447A', 'The allocation to the fixed–satellite service (Earth-to-space) is limited to feeder links of non-geostationary-satellite systems in the mobile–satellite service and is subject to coordination under No. 9.11A.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('447B', 'Additional allocation: the band 5 150–5 216 MHz is also allocated to the fixed– satellite service (space-to-Earth) on a primary basis. This allocation is limited to feeder links of non-geostationary-satellite systems in the mobile–satellite service and is subject to provisions of No. 9.11A. The power flux-density at the Earth''s surface produced by space stations of the fixed–satellite service operating in the space-to-Earth direction in the band 5 150–5 216 MHz shall in no case exceed −164 dB(W/m2) in any kHz band for all angles of arrival.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('447C', 'Administrations responsible for fixed–satellite service networks in the band 5 150–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('199', '5. Satellite networks operated under No. 446 brought into use after 17 November shall not claim protection from, and shall not cause harmful interference to, stations of the fixed–satellite service operated under Nos. 447A and 447B. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('176', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('447D', 'The allocation of the band 5 250–5 255 MHz to the space research service on a primary basis is limited to active spaceborne sensors. Other uses of the band by the space research service are on a secondary basis.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('447E', 'Additional allocation: the frequency band 5 250–5 350 MHz is also allocated to the fixed service on a primary basis in the following countries in Region 3: Australia, Korea (Rep. of), India, Indonesia, Iran (Islamic Republic of), Japan, Malaysia, Papua New Guinea, the Philippines, Dem. People’s Rep. of Korea, Sri Lanka, Thailand and Viet Nam. The use of this frequency band by the fixed service is intended for the implementation of fixed wireless access systems and shall comply with Recommendation ITU-R F.1613-0. In addition, the fixed service shall not claim protection from the radiodetermination, Earth exploration–satellite (active) and space research (active) services, but the provisions of No. 43A do not apply to the fixed service with respect to the Earth exploration–satellite (active) and space research (active) services. After implementation of fixed wireless access systems in the fixed service with protection for the existing radiodetermination systems, no more stringent constraints should be imposed on the fixed wireless access systems by future radiodetermination implementations. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('447F', 'In the frequency band 5 250–5 350 MHz, stations in the mobile service shall not claim protection from the radiolocation service, the Earth exploration–satellite service (active) and the space research service (active). The radiolocation service, the Earth exploration–satellite service (active) and the space research service (active) shall not impose more stringent conditions upon the mobile service than those stipulated in Resolution 229 (Rev.WRC-19). ( ) WRC-19 Additional allocation: in Kyrgyzstan, Romania and Turkmenistan, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('448A', 'The Earth exploration–satellite (active) and space research (active) services in the frequency band 5 250–5 350 MHz shall not claim protection from the radiolocation service. No. 43A does not apply. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('448B', 'The Earth exploration–satellite service (active) operating in the band 5 350–5 570 MHz and space research service (active) operating in the band 5 460–5 570 MHz shall not cause harmful interference to the aeronautical radionavigation service in the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('350', '–5 460 MHz, the radionavigation service in the band 5 460–5 470 MHz and the maritime radionavigation service in the band 5 470–5 570 MHz. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('448C', 'The space research service (active) operating in the band 5 350–5 460 MHz shall not cause harmful interference to nor claim protection from other services to which this band is allocated. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('448D', 'In the frequency band 5 350–5 470 MHz, stations in the radiolocation service shall not cause harmful interference to, nor claim protection from, radar systems in the aeronautical radionavigation service operating in accordance with No. 449. ( ) WRC-03 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('177', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('450A', 'In the frequency band 5 470–5 725 MHz, stations in the mobile service shall not claim protection from radiodetermination services. The radiodetermination services shall not impose more stringent conditions upon the mobile service than those stipulated in Resolution 229 (Rev.WRC-19). ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('450B', 'In the frequency band 5 470–5 650 MHz, stations in the radiolocation service, except ground-based radars used for meteorological purposes in the band 5 600–5 650 MHz, shall not cause harmful interference to, nor claim protection from, radar systems in the maritime radionavigation service. ( ) WRC-03 Additional allocation: in the United Kingdom, the band 5 470–5 850 MHz is also allocated to the land mobile service on a secondary basis. The power limits specified in Nos. 21.2, 21.3, 21.4 and 21.5 shall apply in the band 5 725–5 850 MHz. Between 5 600 MHz and 5 650 MHz, ground-based radars used for meteorological purposes are authorized to operate on a basis of equality with stations of the maritime radionavigation service. Additional allocation: in Saudi Arabia, Bahrain, Bangladesh, Brunei Darussalam, Cameroon, China, Congo (Rep. of the), Korea (Rep. of), Côte d’Ivoire, Djibouti, Egypt, the United Arab Emirates, Eswatini, Gabon, Guinea, Equatorial Guinea, India, Indonesia, Iran (Islamic Republic of), Iraq, Japan, Jordan, Kenya, Kuwait, Lebanon, Libya, Madagascar, Malaysia, Niger, Nigeria, Oman, Uganda, Pakistan, the Philippines, Qatar, the Syrian Arab Republic, the Dem. People’s Rep. of Korea, Singapore, Sri Lanka, Tanzania, Chad, Thailand, Togo, Viet Nam and Yemen, the frequency band 5 650–5 850 MHz is also allocated to the fixed and mobile services on a primary basis. In this case, the provisions of Resolution 229 (Rev.WRC-19) do not apply. In addition, in Afghanistan, Angola, Benin, Bhutan, Botswana, Burkina Faso, Burundi, Dem. Rep. of the Congo, Fiji, Ghana, Kiribati, Lesotho, Malawi, Maldives, Mauritius, Micronesia, Mongolia, Mozambique, Myanmar, Namibia, Nauru, New Zealand, Papua New Guinea, Rwanda, Solomon Islands, South Sudan, South Africa, Tonga, Vanuatu, Zambia and Zimbabwe, the frequency band 5 725–5 850 MHz is allocated to the fixed service on a primary basis, and stations operating in the fixed service shall not cause harmful interference to and shall not claim protection from other primary services in the frequency band. (WRC-19) Different category of service: in Azerbaijan, the Russian Federation, Georgia, Kyrgyzstan, Tajikistan and Turkmenistan, the allocation of the band 5 670–5 725 MHz to the space research service is on a primary basis (see No. 33). ( ) WRC-12 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('178', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('640', 'MHz (ground-to-HAPS direction) may also be used by gateway links for high- altitude platform stations (HAPS) within the territory of these countries. Such use is limited to operation in HAPS gateway links and shall not cause harmful interference to, and shall not claim protection from, existing services, and shall be in compliance with Resolution 150 (WRC-12). Existing services shall not be constrained in future development by HAPS gateway links. The use of HAPS gateway links in these bands requires explicit agreement with other administrations whose territories are located within 1 000 kilometres from the border of an administration intending to use the HAPS gateway links.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('457A', 'In the frequency bands 5 925–6 425 MHz and 14–14.5 GHz, earth stations located on board vessels may communicate with space stations of the fixed–satellite service. Such use shall be in accordance with Resolution 902 (WRC-03). In the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('925', '–6 425 MHz, earth stations located on board vessels and communicating with space stations of the fixed–satellite service may employ transmit antennas with minimum diameter of 1.2 m and operate without prior agreement of any administration if located at least 330 km away from the low-water mark as officially recognised by the coastal State. All other provisions of Resolution 902 (WRC-03) shall apply. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('457B', 'In the frequency bands 5 925–6 425 MHz and 14–14.5 GHz, earth stations located on board vessels may operate with the characteristics and under the conditions contained in Resolution 902 (WRC-03) in Algeria, Saudi Arabia, Bahrain, Comoros, Djibouti, Egypt, United Arab Emirates, Jordan, Kuwait, Libya, Morocco, Mauritania, Oman, Qatar, the Syrian Arab Republic, Sudan, Tunisia and Yemen, in the maritime mobile– satellite service on a secondary basis. Such use shall be in accordance with Resolution 902 (WRC-03). ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('457C', 'In Region 2 (except Brazil, Cuba, French overseas departments and communities, Guatemala, Mexico, Paraguay, Uruguay and Venezuela), the frequency band 5 925–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('700', 'MHz may be used for aeronautical mobile telemetry for flight testing by aircraft stations (see No. 1.83). Such use shall be in accordance with Resolution 416 (WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('179', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('458A', 'In making assignments in the band 6 700–7 075 MHz to space stations of the fixed– satellite service, administrations are urged to take all practicable steps to protect spectral line observations of the radio astronomy service in the band 6 650–6 675.2 MHz from harmful interference from unwanted emissions.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('458B', 'The space-to-Earth allocation to the fixed–satellite service in the band 6 700–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('075', 'MHz is limited to feeder links for non-geostationary-satellite systems of the mobile–satellite service and is subject to coordination under No. 9.11A. The use of the band 6 700–7 075 MHz (space-to-Earth) by feeder links for non-geostationary-satellite systems in the mobile–satellite service is not subject to No. 22.2. Additional allocation: in the Russian Federation, the frequency bands 7 100–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('235', 'MHz shall not claim protection from existing and future stations of the fixed and mobile services and No. 43A does not apply. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('460A', 'The use of the frequency band 7 190–7 250 MHz (Earth-to-space) by the Earth exploration–satellite service shall be limited to tracking, telemetry and command for the operation of spacecraft. Space stations operating in the Earth exploration–satellite service (Earth-to-space) in the frequency band 7 190–7 250 MHz shall not claim protection from existing and future stations in the fixed and mobile services, and No. 43A does not apply. No. 17 applies. Additionally, to ensure protection of the existing and future deployment of fixed and mobile services, the location of earth stations supporting spacecraft in the Earth exploration–satellite service in non- geostationary orbits or geostationary orbit shall maintain a separation distance of at least 10 km and 50 km, respectively, from the respective border(s) of neighbouring countries, unless a shorter distance is otherwise agreed between the corresponding administrations. (WRC-15)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('460B', 'Space stations on the geostationary orbit operating in the Earth exploration–satellite service (Earth-to-space) in the frequency band 7 190–7 235 MHz shall not claim protection from existing and future stations of the space research service, and No. 43A does not apply. ( ) WRC-15 Additional allocation: the bands 7 250–7 375 MHz (space-to-Earth) and 7 900–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('025', 'MHz (Earth-to-space) are also allocated to the mobile–satellite service on a primary basis, subject to agreement obtained under No. 9.21. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('180', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('461A', 'The use of the band 7 450–7 550 MHz by the meteorological–satellite service (space- to-Earth) is limited to geostationary-satellite systems. Non-geostationary meteorological–satellite systems in this band notified before 30 November 1997 may continue to operate on a primary basis until the end of their lifetime. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('461AA', 'The use of the frequency band 7 375–7 750 MHz by the maritime mobile–satellite service is limited to geostationary-satellite networks. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('461AB', 'In the frequency band 7 375–7 750 MHz, earth stations in the maritime mobile–satellite service shall not claim protection from, nor constrain the use and development of, stations in the fixed and mobile, except aeronautical mobile, services. No. 43A does not apply. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('461B', 'The use of the band 7 750–7 900 MHz by the meteorological–satellite service (space- to-Earth) is limited to non-geostationary-satellite systems. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('462A', 'In Regions 1 and 3 (except for Japan), in the band 8 025–8 400 MHz, the Earth exploration–satellite service using geostationary-satellites shall not produce a power flux-density in excess of the following values for angles of arrival (), without the consent of the affected administration: −135 dB(W/m2) in a 1 MHz band for 0 ≤  < 5 −135 + 0.5 ( − 5) dB(W/m2) in a 1 MHz band for 5 ≤  < 25 −125 dB(W/m2) in a 1 MHz band for 25 ≤  ≤ 90 Aircraft stations are not permitted to transmit in the band 8 025–8 400 MHz. (WRC-97) In the space research service, the use of the band 8 400–8 450 MHz is limited to deep space. Different category of service: in Singapore and Sri Lanka, the allocation of the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('181', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('469A', 'In the band 8 550–8 650 MHz, stations in the Earth exploration–satellite service (active) and space research service (active) shall not cause harmful interference to, or constrain the use and development of, stations of the radiolocation service. (WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('473A', 'In the band 9 000–9 200 MHz, stations operating in the radiolocation service shall not cause harmful interference to, nor claim protection from, systems identified in No. 337 operating in the aeronautical radionavigation service, or radar systems in the maritime radionavigation service operating in this band on a primary basis in the countries listed in No. 471. ( ) WRC-07 In the band 9 200–9 500 MHz, search and rescue transponders (SART) may be used, having due regard to the appropriate ITU-R Recommendation (see also Article 31).');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('474A', 'The use of the frequency band 9 200–9 300 MHz and 9 900–10 400 MHz by the Earth exploration–satellite service (active) is limited to systems requiring necessary bandwidth greater than 600 MHz that cannot be fully accommodated within the frequency band 9 300–9 900 MHz. Such use is subject to agreement to be obtained under No. 9.21 from Algeria, Saudi Arabia, Bahrain, Egypt, Indonesia, Iran (Islamic Republic of), Lebanon and Tunisia. An administration that has not replied under No. 9.52 is considered as not having agreed to the coordination request. In this case, the notifying administration of the satellite system operating in the Earth exploration– satellite service (active) may request the assistance of the Bureau under Sub-Section IID of Article 9. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('474B', 'Stations operating in the Earth exploration–satellite (active) service shall comply with Recommendation ITU-R RS.2066-0. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('474C', 'Stations operating in the Earth exploration–satellite (active) service shall comply with Recommendation ITU-R RS.2065-0. ( ) WRC-15 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('474D', 'Stations in the Earth exploration–satellite service (active) shall not cause harmful interference to, or claim protection from, stations of the maritime radionavigation and radiolocation services in the frequency band 9 200–9 300 MHz, the radionavigation and radiolocation services in the frequency band 9 900–10 000 MHz and the radiolocation service in the frequency band 10.0–10.4 GHz. ( ) WRC-15 The use of the band 9 300–9 500 MHz by the aeronautical radionavigation service is limited to airborne weather radars and ground-based radars. In addition, ground-based radar beacons in the aeronautical radionavigation service are permitted in the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('475A', 'The use of the band 9 300–9 500 MHz by the Earth exploration–satellite service (active) and the space research service (active) is limited to systems requiring necessary bandwidth greater than 300 MHz than cannot be fully accommodated within the 9 500–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('800', 'MHz band. ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('475B', 'In the band 9 300–9 500 MHz, stations operating in the radiolocation service shall not cause harmful interference to, nor claim protection from, radars operating in the radionavigation service in conformity with the Radio Regulations. Ground-based radars used for meteorological purposes have priority over other radiolocation uses. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('476A', 'In the band 9 300–9 800 MHz, stations in the Earth exploration–satellite service (active) and space research service (active) shall not cause harmful interference to, nor claim protection from, stations of the radionavigation and radiolocation services. ( ) WRC-07 Different category of service: in Algeria, Saudi Arabia, Bahrain, Bangladesh, Brunei Darussalam, Cameroon, Djibouti, Egypt, the United Arab Emirates, Eritrea, Ethiopia, Guyana, India, Indonesia, Iran (Islamic Republic of), Iraq, Jamaica, Japan, Jordan, Kuwait, Lebanon, Liberia, Malaysia, Nigeria, Oman, Uganda, Pakistan, Qatar, Syrian Arab Republic, the Dem. People’s Rep. of Korea, Singapore, Somalia, Sudan, South Sudan, Trinidad and Tobago, and Yemen, the allocation of the frequency band 9 800–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('478A', 'The use of the band 9 800–9 900 MHz by the Earth exploration–satellite service (active) and the space research service (active) is limited to systems requiring necessary bandwidth greater than 500 MHz that cannot be fully accommodated within the 9 300–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('478B', 'In the band 9 800–9 900 MHz, stations in the Earth exploration–satellite service (active) and space research service (active) shall not cause harmful interference to, nor Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('183', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('482A', 'For sharing of the band 10.6–10.68 GHz between the Earth exploration–satellite (passive) service and the fixed and mobile, except aeronautical mobile, services, Resolution 751 (WRC-07) applies. ( ) WRC-07 Additional allocation: in Saudi Arabia, Armenia, Azerbaijan, Bahrain, Belarus, China, Colombia, Korea (Rep. of), Egypt, the United Arab Emirates, Georgia, Iran (Islamic Republic of), Iraq, Israel, Jordan, Kazakhstan, Kuwait, Lebanon, Mongolia, Qatar, Kyrgyzstan, the Dem. People’s Rep. of Korea, Tajikistan, Turkmenistan and Yemen, the frequency band 10.68–10.7 GHz is also allocated to the fixed and mobile, except aeronautical mobile, services on a primary basis. Such use is limited to equipment in operation by 1 January 1985. (WRC-19) In Region 1, the use of the band 10.7–11.7 GHz by the fixed–satellite service (Earth- to-space) is limited to feeder links for the broadcasting–satellite service. Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('184', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('484A', 'The use of the bands 10.95–11.2 GHz (space-to-Earth), 11.45–11.7 GHz (space-to- Earth), 11.7–12.2 GHz (space-to-Earth) in Region 2, 12.2–12.75 GHz (space-to-Earth) in Region 3, 12.5–12.75 GHz (space-to-Earth) in Region 1, 13.75–14.5 GHz (Earth-to- space), 17.8–18.6 GHz (space-to-Earth), 19.7–20.2 GHz (space-to-Earth), 27.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('28', '.6 GHz (Earth-to-space), 29.5–30 GHz (Earth-to-space) by a non-geostationary- satellite system in the fixed–satellite service is subject to application of the provisions of No. 9.12 for coordination with other non-geostationary-satellite systems in the fixed–satellite service. Non-geostationary-satellite systems in the fixed–satellite service shall not claim protection from geostationary-satellite networks in the fixed–satellite service operating in accordance with the Radio Regulations, irrespective of the dates of receipt by the Bureau of the complete coordination or notification information, as appropriate, for the non-geostationary-satellite systems in the fixed–satellite service and of the complete coordination or notification information, as appropriate, for the geostationary-satellite networks, and No. 43A does not apply. Non-geostationary- satellite systems in the fixed–satellite service in the above bands shall be operated in such a way that any unacceptable interference that may occur during their operation shall be rapidly eliminated. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('484B', 'Resolution 155 (WRC-15) shall apply. ( ) WRC-15 In Region 2, in the band 11.7–12.2 GHz, transponders on space stations in the fixed– satellite service may be used additionally for transmissions in the broadcasting–satellite service, provided that such transmissions do not have a maximum e.i.r.p. greater than dBW per television channel and do not cause greater interference or require more protection from interference than the coordinated fixed–satellite service frequency assignments. With respect to the space services, this band shall be used principally for the fixed–satellite service. Different category of service: in the United States, the allocation of the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('487A', 'Additional allocation: in Region 1, the band 11.7–12.5 GHz, in Region 2, the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('185', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('186', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('498A', 'The Earth exploration–satellite (active) and space research (active) services operating in the band 13.25–13.4 GHz shall not cause harmful interference to, or constrain the use and development of, the aeronautical radionavigation service. ( ) WRC-97 Additional allocation: in Bangladesh and India, the band 13.25–14 GHz is also allocated to the fixed service on a primary basis. In Pakistan, the band 13.25–13.75 GHz is allocated to the fixed service on a primary basis. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('499A', 'The use of the frequency band 13.4–13.65 GHz by the fixed–satellite service (space- to-Earth) is limited to geostationary–satellite systems and is subject to agreement obtained under No. 9.21 with respect to satellite systems operating in the space research service (space-to-space) to relay data from space stations in the geostationary-satellite orbit to associated space stations in non-geostationary satellite orbits for which advance publication information has been received by the Bureau by 27 November');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('201', '5. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('499B', 'Administrations shall not preclude the deployment and operation of transmitting earth stations in the standard frequency and time signal–satellite service (Earth-to-space) allocated on a secondary basis in the frequency band 13.4–13.65 GHz due to the primary allocation to the fixed satellite service (space-to-Earth). ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('499C', 'The allocation of the frequency band 13.4–13.65 GHz to the space research service on a primary basis is limited to: • satellite systems operating in the space research service (space-to-space) to relay data from space stations in the geostationary-satellite orbit to associated space stations in non-geostationary satellite orbits for which advance publication information has been received by the Bureau by 27 November 2015, • active spaceborne sensors, • satellite systems operating in the space research service (space-to-Earth) to relay data from space stations in the geostationary-satellite orbit to associated earth stations. Other uses of the frequency band by the space research service are on a secondary basis. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('499D', 'In the frequency band 13.4–13.65 GHz, satellite systems in the space research service (space-to-Earth) and/or the space research service (space-to-space) shall not cause harmful interference to, nor claim protection from, stations in the fixed, mobile, radiolocation and Earth exploration–satellite (active) services. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('499E', 'In the frequency band 13.4–13.65 GHz, geostationary-satellite networks in the fixed– satellite service (space-to-Earth) shall not claim protection from space stations in the Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('187', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('13', '.75 GHz is also allocated to the fixed and mobile services on a primary basis. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('501A', 'The allocation of the frequency band 13.65–13.75 GHz to the space research service on a primary basis is limited to active spaceborne sensors. Other uses of the frequency band by the space research service are on a secondary basis. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('501B', 'In the band 13.4–13.75 GHz, the Earth exploration–satellite (active) and space research (active) services shall not cause harmful interference to, or constrain the use and development of, the radiolocation service. ( ) WRC-97 In the band 13.75–14 GHz, an Earth station of a geostationary fixed–satellite service network shall have a minimum antenna diameter of 1.2 m and an Earth station of a non- geostationary fixed–satellite service system shall have a minimum antenna diameter of');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('188', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('504A', 'In the band 14–14.5 GHz, aircraft Earth stations in the secondary aeronautical mobile– satellite service may also communicate with space stations in the fixed–satellite service. The provisions of Nos. 29, 30 and 31 apply. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('504B', 'Aircraft Earth stations operating in the aeronautical mobile–satellite service in the frequency band 14–14.5 GHz shall comply with the provisions of Annex 1, Part C of Recommendation ITU-R M.1643-0, with respect to any radio astronomy station performing observations in the 14.47–14.5 GHz frequency band located on the territory of Spain, France, India, Italy, the United Kingdom and South Africa. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('504C', 'In the frequency band 14–14.25 GHz, the power flux-density produced on the territory of the countries of Saudi Arabia, Bahrain, Botswana, Côte d’Ivoire, Egypt, Guinea, India, Iran (Islamic Republic of), Kuwait, Nigeria, Oman, the Syrian Arab Republic and Tunisia by any aircraft earth station in the aeronautical mobile–satellite service shall not exceed the limits given in Annex 1, Part B of Recommendation ITU-R M.1643-0, unless otherwise specifically agreed by the affected Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('189', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('506A', 'In the band 14–14.5 GHz, ship Earth stations with an e.i.r.p. greater than 21 dBW shall operate under the same conditions as Earth stations located on board vessels, as provided in Resolution 902 (WRC-03). This footnote shall not apply to ship Earth stations for which the complete Appendix 4 information has been received by the Bureau prior to 5 July 2003. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('506B', 'Earth stations located on board vessels communicating with space stations in the fixed– satellite service may operate in the frequency band 14–14.5 GHz without the need for prior agreement from Cyprus, and Malta, within the minimum distance given in Resolution 902 (WRC-03) from these countries. ( ) WRC-15 Additional allocation: in Germany, France, Italy, Libya, North Macedonia and the United Kingdom, the frequency band 14.25–14.3 GHz is also allocated to the fixed service on a primary basis. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('508A', 'In the frequency band 14.25–14.3 GHz, the power flux-density produced on the territory of the countries of Saudi Arabia, Bahrain, Botswana, China, Côte d’Ivoire, Egypt, France, Guinea, India, Iran (Islamic Republic of), Italy, Kuwait, Nigeria, Oman, the Syrian Arab Republic, the United Kingdom and Tunisia by any aircraft earth station in the aeronautical mobile–satellite service shall not exceed the limits given in Annex 1, Part B of Recommendation ITU-R M.1643-0, unless otherwise specifically agreed by the affected administration(s). The provisions of this footnote in no way derogate the obligations of the aeronautical mobile–satellite service to operate as a secondary service in accordance with No. 29. (WRC-15)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('509A', 'In the frequency band 14.3–14.5 GHz, the power flux-density produced on the territory of the countries of Saudi Arabia, Bahrain, Botswana, Cameroon, China, Côte d’Ivoire, Egypt, France, Gabon, Guinea, India, Iran (Islamic Republic of), Italy, Kuwait, Morocco, Nigeria, Oman, the Syrian Arab Republic, the United Kingdom, Sri Lanka, Tunisia and Viet Nam by any aircraft earth station in the aeronautical mobile–satellite Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('509B', 'The use of the frequency bands 14.5–14.75 GHz in countries listed in Resolution 163 (WRC-15) and 14.5–14.8 GHz in countries listed in Resolution 164 (WRC-15) by the fixed–satellite service (Earth-to-space) not for feeder links for the broadcasting– satellite service is limited to geostationary-satellites. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('509C', 'For the use of the frequency bands 14.5–14.75 GHz in countries listed in Resolution 163 (WRC-15) and 14.5–14.8 GHz in countries listed in Resolution 164 ( ) by the fixed–satellite service (Earth-to-space) not for feeder links for the WRC-15 broadcasting–satellite service, the fixed–satellite service earth stations shall have a minimum antenna diameter of 6 m and a maximum power spectral density of −44.5 dBW/Hz at the input of the antenna. The earth stations shall be notified at known locations on land. (WRC-15)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('509D', 'Before an administration brings into use an earth station in the fixed–satellite service (Earth-to-space) not for feeder links for the broadcasting–satellite service in the frequency bands 14.5–14.75 GHz (in countries listed in Resolution 163 (WRC-15)) and 14.5–14.8 GHz (in countries listed in Resolution 164 (WRC-15)), it shall ensure that the power flux-density produced by this earth station does not exceed −151.5 dB(W/(m2·4 kHz) produced at all altitudes from 0 m to 19 000 m above sea level at 22 km seaward from all coasts, defined as the low-water mark, as officially recognised by each coastal State. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('509E', 'In the frequency bands 14.5–14.75 GHz in countries listed in Resolution 163 (WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('509F', 'In the frequency bands 14.5–14.75 GHz in countries listed in Resolution 163 (WRC-');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('509G', 'The frequency band 14.5–14.8 GHz is also allocated to the space research service on a primary basis. However, such use is limited to the satellite systems operating in the space research service (Earth-to-space) to relay data to space stations in the geostationary–satellite orbit from associated earth stations. Stations in the space research service shall not cause harmful interference to, or claim protection from, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('191', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('511A', 'Use of the frequency band 15.43–15.63 GHz by the fixed–satellite service (Earth-to- space) is limited to feeder links of non-geostationary systems in the mobile–satellite service, subject to coordination under No. 9.11A. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('511C', 'Stations operating in the aeronautical radionavigation service shall limit the effective e.i.r.p. in accordance with Recommendation ITU-R S.1340-0. The minimum coordination distance required to protect the aeronautical radionavigation stations (No. 4.10 applies) from harmful interference from feeder-link earth stations and the maximum e.i.r.p. transmitted towards the local horizontal plane by a feeder-link earth station shall be in accordance with Recommendation ITU-R S.1340-0. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('511E', 'In the frequency band 15.4–15.7 GHz, stations operating in the radiolocation service shall not cause harmful interference to, or claim protection from, stations operating in the aeronautical radionavigation service.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('511F', 'In order to protect the radio astronomy service in the frequency band 15.35–15.4 GHz, radiolocation stations operating in the frequency band 15.4–15.7 GHz shall not exceed the power flux-density level of −156 dB(W/m2) in a 50 MHz bandwidth in the frequency band 15.35–15.4 GHz, at any radio astronomy observatory site for more than per cent of the time. Additional allocation: in Algeria, Saudi Arabia, Austria, Bahrain, Bangladesh, Brunei Darussalam, Cameroon, Congo (Rep. of the), Egypt, El Salvador, the United Arab Emirates, Eritrea, Finland, Guatemala, India, Indonesia, Iran (Islamic Republic of), Jordan, Kenya, Kuwait, Lebanon, Libya, Malaysia, Mali, Morocco, Mauritania, Montenegro, Nepal, Nicaragua, Niger, Oman, Pakistan, Qatar, Syrian Arab Republic, the Dem. Rep. of the Congo, Singapore, Somalia, Sudan, South Sudan, Chad, Togo and Yemen, the frequency band 15.7–17.3 GHz is also allocated to the fixed and mobile services on a primary basis. (WRC-15) Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('192', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('513A', 'Spaceborne active sensors operating in the band 17.2–17.3 GHz shall not cause harmful interference to, or constrain the development of, the radiolocation and other services allocated on a primary basis. ( ) WRC-97 Additional allocation: in Algeria, Saudi Arabia, Bahrain, Bangladesh, Cameroon, El Salvador, the United Arab Emirates, Guatemala, India, Iran (Islamic Republic of), Iraq, Israel, Italy, Japan, Jordan, Kuwait, Libya, Lithuania, Nepal, Nicaragua, Nigeria, Oman, Uzbekistan, Pakistan, Qatar, Kyrgyzstan, Sudan and South Sudan, the frequency band 17.3–17.7 GHz is also allocated to the fixed and mobile services on a secondary basis. The power limits given in Nos. 21.3 and 21.5 shall apply. ( ) WRC-15 In the band 17.3–17.8 GHz, sharing between the fixed–satellite service (Earth-to-space) and the broadcasting–satellite service shall also be in accordance with the provisions of § 1 of Annex 4 of Appendix 30A. The use of the band 17.3–18.1 GHz by geostationary-satellite systems in the fixed– satellite service (Earth-to-space) is limited to feeder links for the broadcasting–satellite service. The use of the band 17.3–17.8 GHz in Region 2 by systems in the fixed– satellite service (Earth-to-space) is limited to geostationary satellites. For the use of the band 17.3–17.8 GHz in Region 2 by feeder links for the broadcasting–satellite service in the band 12.2–12.7 GHz, see Article 11. The use of the bands 17.3–18.1 GHz (Earth- to-space) in Regions 1 and 3 and 17.8–18.1 GHz (Earth-to-space) in Region 2 by non- geostationary-satellite systems in the fixed–satellite service is subject to application of the provisions of No. 9.12 for coordination with other non-geostationary-satellite systems in the fixed–satellite service. Non-geostationary-satellite systems in the fixed– satellite service shall not claim protection from geostationary-satellite networks in the fixed–satellite service operating in accordance with the Radio Regulations, irrespective of the dates of receipt by the Bureau of the complete coordination or notification information, as appropriate, for the non-geostationary-satellite systems in the fixed– satellite service and of the complete coordination or notification information, as appropriate, for the geostationary-satellite networks, and No. 43A does not apply. Non- geostationary-satellite systems in the fixed–satellite service in the above bands shall be operated in such a way that any unacceptable interference that may occur during their operation shall be rapidly eliminated. (WRC-2000)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('516A', 'In the band 17.3–17.7 GHz, Earth stations of the fixed–satellite service (space-to-Earth) in Region 1 shall not claim protection from the broadcasting–satellite service feeder- link Earth stations operating under Appendix 30A, nor put any limitations or restrictions on the locations of the broadcasting–satellite service feeder-link Earth stations anywhere within the service area of the feeder link. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('516B', 'The following bands are identified for use by high-density applications in the fixed– satellite service: Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('193', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('17', '.3–17.7 GHz (space-to-Earth) in Region 1,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('18', '.3–19.3 GHz (space-to-Earth) in Region 2,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('39', '.5–40 GHz (space-to-Earth) in Region 1,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('47', '.5–47.9 GHz (space-to-Earth) in Region 1,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('49', '.44–50.2 GHz (space-to-Earth) in Region 1, and');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('27', '.5–27.82 GHz (Earth-to-space) in Region 1,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('29', '.25–29.46 GHz (Earth-to-space) in Region 2,');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('517A', 'The operation of earth stations in motion communicating with geostationary fixed– satellite service space stations within the frequency bands 17.7–19.7 GHz (space-to- Earth) and 27.5–29.5 GHz (Earth-to-space) shall be subject to the application of Resolution 169 (WRC-19). ( ) WRC-19 Additional allocation: the bands 18–18.3 GHz in Region 2 and 18.1–18.4 GHz in Regions 1 and 3 are also allocated to the meteorological–satellite service (space-to- Earth) on a primary basis. Their use is limited to geostationary satellites. ( ) WRC-07 The use of the band 18.1–18.4 GHz by the fixed–satellite service (Earth-to-space) is limited to feeder links of geostationary-satellite systems in the broadcasting–satellite service. ( ) WRC-2000 Alternative allocation: in the United Arab Emirates and Greece, the frequency band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('194', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('522A', 'The emissions of the fixed service and the fixed–satellite service in the band 18.6–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('522B', 'The use of the band 18.6–18.8 GHz by the fixed–satellite service is limited to geostationary systems and systems with an orbit of apogee greater than');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('522C', 'In the band 18.6–18.8 GHz, in Algeria, Saudi Arabia, Bahrain, Egypt, the United Arab Emirates, Jordan, Lebanon, Libyan Arab Jamahiriya, Morocco, Oman, Qatar, the Syrian Arab Republic, Tunisia and Yemen, fixed-service systems in operation at the date of entry into force of the Final Acts of WRC-2000 are not subject to the limits of No. 21.5A. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('523A', 'The use of the bands 18.8–19.3 GHz (space-to-Earth) and 28.6–29.1 GHz (Earth-to- space) by geostationary and non-geostationary fixed–satellite service networks is subject to the application of the provisions of No. 9.11A and No. 22.2 does not apply. Administrations having geostationary-satellite networks under coordination prior to November 1995 shall cooperate to the maximum extent possible to coordinate pursuant to No. 9.11A with non-geostationary-satellite networks for which notification information has been received by the Bureau prior to that date, with a view to reaching results acceptable to all the parties concerned. Non-geostationary-satellite networks shall not cause unacceptable interference to geostationary fixed–satellite service networks for which complete Appendix 4 notification information is considered as having been received by the Bureau prior to 18 November 1995. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('523B', 'The use of the band 19.3–19.6 GHz (Earth-to-space) by the fixed–satellite service is limited to feeder links for non-geostationary-satellite systems in the mobile–satellite service. Such use is subject to the application of the provisions of No. 9.11A, and No. 22.2 does not apply.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('523C', 'No. 22.2 shall continue to apply in the bands 19.3–19.6 GHz and 29.1–29.4 GHz between feeder links of non-geostationary mobile–satellite service networks and those fixed–satellite service networks for which complete Appendix 4 coordination information, or notification information, is considered as having been received by the Bureau prior to 18 November 1995. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('523D', 'The use of the band 19.3–19.7 GHz (space-to-Earth) by geostationary fixed–satellite service systems and by feeder links for non-geostationary-satellite systems in the mobile–satellite service is subject to the application of the provisions of No. 9.11A, but not subject to the provisions of No. 22.2. The use of this band for other non- geostationary fixed–satellite service systems, or for the cases indicated in Nos. 523C and 523E, is not subject to the provisions of No. 9.11A and shall continue to be subject to Articles 9 (except No. 9.11A) and 11 procedures, and to the provisions of No. 22.2. ( ) WRC-97 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('195', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('523E', 'No. 22.2 shall continue to apply in the bands 19.6–19.7 GHz and 29.4–29.5 GHz, between feeder links of non-geostationary mobile–satellite service networks and those fixed–satellite service networks for which complete Appendix 4 coordination information, or notification information, is considered as having been received by the Bureau by 21 November 1997. ( ) WRC-97 Additional allocation: in Afghanistan, Algeria, Saudi Arabia, Bahrain, Brunei Darussalam, Cameroon, China, Congo (Rep. of the), Costa Rica, Egypt, the United Arab Emirates, Gabon, Guatemala, Guinea, India, Iran (Islamic Republic of), Iraq, Israel, Japan, Jordan, Kuwait, Lebanon, Malaysia, Mali, Morocco, Mauritania, Nepal, Nigeria, Oman, Pakistan, the Philippines, Qatar, the Syrian Arab Republic, the Dem. Rep. of the Congo, the Dem. People’s Rep. of Korea, Singapore, Somalia, Sudan, South Sudan, Chad, Togo and Tunisia, the frequency band 19.7–21.2 GHz is also allocated to the fixed and mobile services on a primary basis. This additional use shall not impose any limitation on the power flux-density of space stations in the fixed–satellite service in the frequency band 19.7–21.2 GHz and of space stations in the mobile–satellite service in the frequency band 19.7–20.2 GHz where the allocation to the mobile– satellite service is on a primary basis in the latter frequency band. (WRC-15) In order to facilitate interregional coordination between networks in the mobile– satellite and fixed–satellite services, carriers in the mobile–satellite service that are most susceptible to interference shall, to the extent practicable, be located in the higher parts of the bands 19.7–20.2 GHz and 29.5–30 GHz. In the bands 19.7–20.2 GHz and 29.5–30 GHz in Region 2, and in the bands 20.1–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('20', '.2 GHz and 29.9–30 GHz in Regions 1 and 3, networks which are both in the fixed– satellite service and in the mobile–satellite service may include links between Earth stations at specified or unspecified points or while in motion, through one or more satellites for point-to-point and point-to-multipoint communications. In the bands 19.7–20.2 GHz and 29.5–30 GHz, the provisions of No. 4.10 do not apply with respect to the mobile–satellite service.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('527A', 'The operation of earth stations in motion communicating with the fixed satellite service is subject to Resolution 156 (WRC-15). ( ) WRC-15 The allocation to the mobile–satellite service is intended for use by networks which use narrow spot-beam antennas and other advanced technology at the space stations. Administrations operating systems in the mobile–satellite service in the band 19.7–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('196', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('530A', 'Unless otherwise agreed between the administrations concerned, any station in the fixed or mobile services of an administration shall not produce a power flux-density in excess of −120.4 dB(W/(m2·MHz)) at 3 m above the ground of any point of the territory of any other administration in Regions 1 and 3 for more than 20% of the time. In conducting the calculations, administrations should use the most recent version of Recommendation ITU-R P.452 (see also the most recent version of Recommendation ITU-R BO.1898). ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('530B', 'In the band 21.4–22 GHz, in order to facilitate the development of the broadcasting– satellite service, administrations in Regions 1 and 3 are encouraged not to deploy stations in the mobile service and are encouraged to limit the deployment of stations in the fixed service to point-to-point links. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('530E', 'The allocation to the fixed service in the frequency band 21.4–22 GHz is identified for use in Region 2 by high-altitude platform stations (HAPS). This identification does not preclude the use of this frequency band by other fixed-service applications or by other services to which it is allocated on a co-primary basis, and does not establish priority in the Radio Regulations. Such use of the fixed-service allocation by HAPS is limited to the HAPS-to-ground direction, and shall be in accordance with the provisions of Resolution 165 (WRC-19). ( WRC-19) Additional allocation: in Japan, the band 21.4–22 GHz is also allocated to the broadcasting service on a primary basis. The use of the band 22.21–22.5 GHz by the Earth exploration–satellite (passive) and space research (passive) services shall not impose constraints upon the fixed and mobile, except aeronautical mobile, services.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('532A', 'The location of earth stations in the space research service shall maintain a separation distance of at least 54 km from the respective border(s) of neighbouring countries to protect the existing and future deployment of fixed and mobile services unless a shorter distance is otherwise agreed between the corresponding administrations. Nos. 9.17 and 9.18 do not apply.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('532B', 'Use of the band 24.65–25.25 GHz in Region 1 and the band 24.65–24.75 GHz in Region 3 by the fixed–satellite service (Earth-to-space) is limited to earth stations using a minimum antenna diameter of 4.5 m. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('532AA', 'The allocation to the fixed service in the frequency band 24.25–25.25 GHz is identified for use in Region 2 by high-altitude platform stations (HAPS). This identification does not preclude the use of this frequency band by other fixed-service applications or by other services to which this frequency band is allocated on a co-primary basis, and does not establish priority in the Radio Regulations. Such use of the fixed-service allocation by HAPS is limited to the HAPS-to-ground direction and shall be in accordance with the provisions of Resolution 166 (WRC-19). ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('532AB', 'The frequency band 24.25–27.5 GHz is identified for use by administrations wishing to implement the terrestrial component of International Mobile Telecommunications Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('197', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('534A', 'The allocation to the fixed service in the frequency band 25.25–27.5 GHz is identified in Region 2 for use by high-altitude platform stations (HAPS) in accordance with the provisions of Resolution 166 (WRC-19). Such use of the fixed-service allocation by HAPS shall be limited to the ground-to-HAPS direction in the frequency band 25.25–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('535A', 'The use of the band 29.1–29.5 GHz (Earth-to-space) by the fixed–satellite service is limited to geostationary-satellite systems and feeder links to non-geostationary-satellite systems in the mobile–satellite service. Such use is subject to the application of the provisions of No. 9.11A, but not subject to the provisions of No. 22.2, except as indicated in Nos. 523C and 523E where such use is not subject to the provisions of No. 9.11A and shall continue to be subject to Articles 9 (except No. 9.11A) and 11 procedures, and to the provisions of No. 22.2. ( ) WRC-97 Use of the 25.25–27.5 GHz band by the inter–satellite service is limited to space research and Earth exploration–satellite applications, and also transmissions of data originating from industrial and medical activities in space.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('536A', 'Administrations operating earth stations in the Earth exploration–satellite service or the space research service shall not claim protection from stations in the fixed and mobile services operated by other administrations. In addition, earth stations in the Earth exploration–satellite service or in the space research service should be operated taking into account the most recent version of Recommendation ITU-R SA.1862. Resolution (WRC-19) applies. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('536B', 'In Algeria, Saudi Arabia, Austria, Bahrain, Belgium, Brazil, China, Korea (Rep. of), Denmark, Egypt, United Arab Emirates, Estonia, Finland, Hungary, India, Iran (Islamic Republic of), Iraq, Ireland, Israel, Italy, Jordan, Kenya, Kuwait, Lebanon, Libya, Lithuania, Moldova, Norway, Oman, Uganda, Pakistan, the Philippines, Poland, Portugal, Qatar, the Syrian Arab Republic, Dem. People’s Rep. of Korea, Slovakia, the Czech Rep., Romania, the United Kingdom, Singapore, Slovenia, Sudan, Sweden, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('198', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('536C', 'In Algeria, Saudi Arabia, Bahrain, Botswana, Brazil, Cameroon, Comoros, Cuba, Djibouti, Egypt, United Arab Emirates, Estonia, Finland, Iran (Islamic Republic of), Israel, Jordan, Kenya, Kuwait, Lithuania, Malaysia, Morocco, Nigeria, Oman, Qatar, Syrian Arab Republic, Somalia, Sudan, South Sudan, Tanzania, Tunisia, Uruguay, Zambia and Zimbabwe, earth stations operating in the space research service in the band 25.5–27 GHz shall not claim protection from, or constrain the use and deployment of, stations of the fixed and mobile services. ( ) WRC-12 Space services using non-geostationary satellites operating in the inter–satellite service in the band 27–27.5 GHz are exempt from the provisions of No. 22.2.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('537A', 'In Bhutan, Cameroon, China, Korea (Rep. of), the Russian Federation, India, Indonesia, Iran (Islamic Republic of), Iraq, Japan, Kazakhstan, Malaysia, Maldives, Mongolia, Myanmar, Uzbekistan, Pakistan, the Philippines, Kyrgyzstan, the Dem. People’s Rep. of Korea, Sudan, Sri Lanka, Thailand and Viet Nam, the allocation to the fixed service in the frequency band 27.9–28.2 GHz may also be used by high altitude platform stations (HAPS) within the territory of these countries. Such use of 300 MHz of the fixed-service allocation by HAPS in the above countries is further limited to operation in the HAPS-to-ground direction and shall not cause harmful interference to, nor claim protection from, other types of fixed-service systems or other co-primary services. Furthermore, the development of these other services shall not be constrained by HAPS. See Resolution 145 (Rev.WRC-19). ( ) WRC-19 Additional allocation: the bands 27.500–27.501 GHz and 29.999–30.000 GHz are also allocated to the fixed–satellite service (space-to-Earth) on a primary basis for the beacon transmissions intended for up-link power control. Such space-to-Earth transmissions shall not exceed an equivalent isotropically radiated power (e.i.r.p.) of +10 dBW in the direction of adjacent satellites on the geostationary-satellite orbit. ( ) WRC-07 The band 27.5–30 GHz may be used by the fixed–satellite service (Earth-to-space) for the provision of feeder links for the broadcasting–satellite service. Additional allocation: the band 27.501–29.999 GHz is also allocated to the fixed– satellite service (space-to-Earth) on a secondary basis for beacon transmissions intended for up-link power control. In the band 28.5–30 GHz, the Earth exploration–satellite service is limited to the transfer of data between stations and not to the primary collection of information by means of active or passive sensors.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('541A', 'Feeder links of non-geostationary networks in the mobile–satellite service and geostationary networks in the fixed–satellite service operating in the band 29.1– Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('543B', 'The allocation to the fixed service in the frequency band 31–31.3 GHz is identified for worldwide use by high-altitude platform stations (HAPS). This identification does not preclude the use of this frequency band by other fixed-service applications or by other services to which this frequency band is allocated on a co-primary basis, and does not establish priority in the Radio Regulations. Such use of the fixed-service allocation by HAPS shall be in accordance with the provisions of Resolution (WRC-19). (WRC-19) In the band 31–31.3 GHz the power flux-density limits specified in Article 21, Table 21–4, shall apply to the space research service. Different category of service: in Armenia, Georgia, Kyrgyzstan, Tajikistan and Turkmenistan, the allocation of the band 31–31.3 GHz to the space research service is on a primary basis (see No. 33). ( ) WRC-12 Different category of service: in Saudi Arabia, Armenia, Azerbaijan, Bahrain, Belarus, Egypt, the United Arab Emirates, Spain, Estonia, the Russian Federation, Georgia, Hungary, Iran (Islamic Republic of), Israel, Jordan, Lebanon, Moldova, Mongolia, Oman, Uzbekistan, Poland, the Syrian Arab Republic, Kyrgyzstan, Romania, the United Kingdom, South Africa, Tajikistan, Turkmenistan and Turkey, the allocation of the frequency band 31.5–31.8 GHz to the fixed and mobile, except aeronautical mobile, services is on a primary basis (see No. 33). (WRC-19) The bands 31.8–33.4 GHz, 37–40 GHz, 40.5–43.5 GHz, 51.4–52.6 GHz, 55.78– GHz and 64–66 GHz are available for high-density applications in the fixed service (see Resolution 75 (WRC-2000)). Administrations should take this into account when Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('547A', 'Administrations should take practical measures to minimize the potential interference between stations in the fixed service and airborne stations in the radionavigation service in the 31.8–33.4 GHz band, taking into account the operational needs of the airborne radar systems. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('547B', 'Alternative allocation: in the United States, the band 31.8–32 GHz is allocated to the radionavigation and space research (deep space) (space-to-Earth) services on a primary basis. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('547C', 'Alternative allocation: in the United States, the band 32–32.3 GHz is allocated to the radionavigation and space research (deep space) (space-to-Earth) services on a primary basis. ( ) WRC-03');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('547D', 'Alternative allocation: in the United States, the band 32.3–33 GHz is allocated to the inter–satellite and radionavigation services on a primary basis. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('547E', 'Alternative allocation: in the United States, the band 33–33.4 GHz is allocated to the radionavigation service on a primary basis. ( ) WRC-97 In designing systems for the inter–satellite service in the band 32.3–33 GHz, for the radionavigation service in the band 32–33 GHz, and for the space research service (deep space) in the band 31.8–32.3 GHz, administrations shall take all necessary measures to prevent harmful interference between these services, bearing in mind the safety aspects of the radionavigation service (see Recommendation 707). (WRC-03) Additional allocation: in Saudi Arabia, Bahrain, Bangladesh, Egypt, the United Arab Emirates, Gabon, Indonesia, Iran (Islamic Republic of), Iraq, Israel, Jordan, Kuwait, Lebanon, Libya, Malaysia, Mali, Morocco, Mauritania, Nepal, Nigeria, Oman, Pakistan, the Philippines, Qatar, the Syrian Arab Republic, the Dem. Rep. of the Congo, Singapore, Somalia, Sudan, South Sudan, Sri Lanka, Togo, Tunisia and Yemen, the band 33.4–36 GHz is also allocated to the fixed and mobile services on a primary basis. ( ) WRC-12');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('549A', 'In the band 35.5–36.0 GHz, the mean power flux-density at the Earth’s surface, generated by any spaceborne sensor in the Earth exploration–satellite service (active) or space research service (active), for any angle greater than 0.8° from the beam centre shall not exceed −73.3 dB(W/m2) in this band. ( ) WRC-03 Different category of service: in Armenia, Azerbaijan, Belarus, the Russian Federation, Georgia, Kyrgyzstan, Tajikistan and Turkmenistan, the allocation of the band 34.7–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('35', '.2 GHz to the space research service is on a primary basis (see No. 33). ( ) WRC-12 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('550A', 'For sharing of the band 36–37 GHz between the Earth exploration–satellite (passive) service and the fixed and mobile services, Resolution 752 (WRC-07) shall apply. ( ) WRC-07');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('550B', 'The frequency band 37–43.5 GHz, or portions thereof, is identified for use by administrations wishing to implement the terrestrial component of International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. Because of the potential deployment of FSS earth stations within the frequency range 37.5–42.5 GHz and high-density applications in the fixed–satellite service in the frequency bands 39.5–40 GHz in Region 1, 40–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('550C', 'The use of the frequency bands 37.5–39.5 GHz (space-to-Earth), 39.5–42.5 GHz (space- to-Earth), 47.2–50.2 GHz (Earth-to-space) and 50.4–51.4 GHz (Earth-to-space) by a non-geostationary-satellite system in the fixed–satellite service is subject to the application of the provisions of No. 9.12 for coordination with other non-geostationary- satellite systems in the fixed–satellite service but not with non-geostationary-satellite systems in other services. Resolution 770 (WRC-19) shall also apply, and No. 22.2 shall continue to apply. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('550D', 'The allocation to the fixed service in the frequency band 38–39.5 GHz is identified for worldwide use by administrations wishing to implement high-altitude platform stations (HAPS). In the HAPS-to-ground direction, the HAPS ground station shall not claim protection from stations in the fixed, mobile and fixed–satellite services; and No. 43A does not apply. This identification does not preclude the use of this frequency band by other fixed-service applications or by other services to which this frequency band is allocated on a co-primary basis and does not establish priority in the Radio Regulations. Furthermore, the development of the fixed–satellite, fixed and mobile services shall not be unduly constrained by HAPS. Such use of the fixed-service allocation by HAPS shall be in accordance with the provisions of Resolution 168 (WRC-19). ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('550E', 'The use of the frequency bands 39.5–40 GHz and 40–40.5 GHz by non-geostationary- satellite systems in the mobile–satellite service (space-to-Earth) and by non- geostationary-satellite systems in the fixed–satellite service (space-to-Earth) is subject to the application of the provisions of No. 9.12 for coordination with other non- geostationary-satellite systems in the fixed–satellite and mobile–satellite services but not with non-geostationary-satellite systems in other services. No. 22.2 shall continue to apply for non-geostationary-satellite-systems. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('551F', 'Different category of service: in Japan, the allocation of the band 41.5–42.5 GHz to the mobile service is on a primary basis (see No. 33). ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('551H', 'The equivalent power flux-density (epfd) produced in the frequency band 42.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('43', '.5 GHz by all space stations in any non-geostationary-satellite system in the fixed– satellite service (space-to-Earth), or in the broadcasting–satellite service operating in Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('42', '.5–43.5 GHz at the site of any radio astronomy station registered as a single-dish telescope; and −209 dB(W/m2) in any 500 kHz of the frequency band 42.5–43.5 GHz at the site of any radio astronomy station registered as a very long baseline interferometry station. These epfd values shall be evaluated using the methodology given in Recommendation ITU-R S.1586-1 and the reference antenna pattern and the maximum gain of an antenna in the radio astronomy service given in Recommendation ITU-R RA.1631-0 and shall apply over the whole sky and for elevation angles higher than the minimum operating angle θmin of the radiotelescope (for which a default value of 5° should be adopted in the absence of notified information). These values shall apply at any radio astronomy station that either: • was in operation prior to 5 July 2003 and has been notified to the Bureau before January 2004; or • was notified before the date of receipt of the complete Appendix 4 information for coordination or notification, as appropriate, for the space station to which the limits apply. Other radio astronomy stations notified after these dates may seek an agreement with administrations that have authorised the space stations. In Region 2, Resolution 743 (WRC-03) shall apply. The limits in this footnote may be exceeded at the site of a radio astronomy station of any country whose administration so agreed. ( ) WRC-15');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('551I', 'The power flux-density in the band 42.5–43.5 GHz produced by any geostationary space station in the fixed–satellite service (space-to-Earth), or the broadcasting–satellite service operating in the 42–42.5 GHz band, shall not exceed the following values at the site of any radio astronomy station: • −137 dB(W/m2) in 1 GHz and −153 dB(W/m2) in any 500 kHz of the 42.5–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('203', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('552A', 'The allocation to the fixed service in the bands 47.2–47.5 GHz and 47.9–48.2 GHz is identified for use by high altitude platform stations (HAPS). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated on a co-primary basis, and does not establish priority in the Radio Regulations. Such use of the fixed-service allocation in the frequency bands 47.2–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('553A', 'In Algeria, Angola, Bahrain, Belarus, Benin, Botswana, Brazil, Burkina Faso, Cabo Verde, Korea (Rep. of), Côte d’Ivoire, Croatia, United Arab Emirates, Estonia, Eswatini, Gabon, Gambia, Ghana, Greece, Guinea, Guinea-Bissau, Hungary, Iran (Islamic Republic of), Iraq, Jordan, Kuwait, Lesotho, Latvia, Liberia, Lithuania, Madagascar, Malawi, Mali, Morocco, Mauritius, Mauritania, Mozambique, Namibia, Niger, Nigeria, Oman, Qatar, Senegal, Seychelles, Sierra Leone, Slovenia, Sudan, South Africa, Sweden, Tanzania, Togo, Tunisia, Zambia and Zimbabwe, the frequency band 45.5–47 GHz is identified for use by administrations wishing to implement the terrestrial component of International Mobile Telecommunications (IMT), taking into account No. 553. With respect to the aeronautical mobile service and radionavigation service, the use of this frequency band for the implementation of IMT is subject to agreement obtained under No. 9.21 with concerned administrations and shall not cause harmful interference to, or claim protection from these services. This identification does not preclude the use of this frequency band by any application of the services to which it is allocated and does not establish priority in the Radio Regulations. Resolution 244 (WRC-19) applies. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('553B', 'In Region 2 and Algeria, Angola, Saudi Arabia, Australia, Bahrain, Benin, Botswana, Burkina Faso, Burundi, Cameroon, Central African Rep., Comoros, Congo (Rep. of the), Korea (Rep. of), Côte d’Ivoire, Djibouti, Egypt, United Arab Emirates, Eswatini, Ethiopia, Gabon, Gambia, Ghana, Guinea, Guinea-Bissau, Equatorial Guinea, India, Iran (Islamic Republic of), Iraq, Japan, Jordan, Kenya, Kuwait, Lesotho, Liberia, Libya, Lithuania, Madagascar, Malaysia, Malawi, Mali, Morocco, Mauritius, Mauritania, Mozambique, Namibia, Niger, Nigeria, Oman, Uganda, Qatar, the Syrian Arab Republic, the Dem. Rep. of the Congo, Rwanda, Sao Tome and Principe, Senegal, Seychelles, Sierra Leone, Singapore, Slovenia, Somalia, Sudan, South Sudan, South Africa, Sweden, Tanzania, Chad, Togo, Tunisia, Zambia and Zimbabwe, the frequency band 47.2–48.2 GHz is identified for use by administrations wishing to implement International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which it is allocated, Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('204', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('554A', 'The use of the bands 47.5–47.9 GHz, 48.2–48.54 GHz and 49.44–50.2 GHz by the fixed–satellite service (space-to-Earth) is limited to geostationary satellites. ( ) WRC-03 Additional allocation: the band 48.94–49.04 GHz is also allocated to the radio astronomy service on a primary basis. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('555B', 'The power flux-density in the band 48.94–49.04 GHz produced by any geostationary space station in the fixed–satellite service (space-to-Earth) operating in the bands 48.2–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('555C', 'The use of the frequency band 51.4–52.4 GHz by the fixed-satellite service (Earth-to- space) is limited to geostationary-satellite networks. The earth stations shall be limited to gateway earth stations with a minimum antenna diameters of 2.4 metres. ( ) WRC-19 In the bands 51.4–54.25 GHz, 58.2–59 GHz and 64–65 GHz, radio astronomy observations may be carried out under national arrangements. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('556A', 'Use of the bands 54.25–56.9 GHz, 57–58.2 GHz and 59–59.3 GHz by the inter–satellite service is limited to satellites in the geostationary satellite orbit. The single entry power flux-density at all altitudes from 0 km to 1 000 km above the Earth''s surface produced by a station in the inter–satellite service, for all conditions and for all methods of modulation, shall not exceed −147 dB(W/(m2·100 MHz)) for all angles of arrival. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('556B', 'Additional allocation: in Japan, the band 54.25–55.78 GHz is also allocated to the mobile service on a primary basis for low-density use. ( ) WRC-97 Additional allocation: in Japan, the band 55.78–58.2 GHz is also allocated to the radiolocation service on a primary basis. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('557A', 'In the band 55.78–56.26 GHz, in order to protect stations in the Earth exploration– satellite service (passive), the maximum power density delivered by a transmitter to the antenna of a fixed service station is limited to −26 dB(W/MHz). ) (WRC-2000 In the bands 55.78–58.2 GHz, 59–64 GHz, 66–71 GHz, 122.25–123 GHz, 130– GHz, 167–174.8 GHz and 191.8–200 GHz, stations in the aeronautical mobile service may be operated subject to not causing harmful interference to the inter–satellite service (see No. 43). ( ) WRC-2000 Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('205', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('558A', 'Use of the band 56.9–57 GHz by inter–satellite systems is limited to links between satellites in geostationary-satellite orbit and to transmissions from non-geostationary satellites in high-Earth orbit to those in low-Earth orbit. For links between satellites in the geostationary-satellite orbit, the single entry power flux-density at all altitudes from km to 1 000 km above the Earth''s surface, for all conditions and for all methods of modulation, shall not exceed −147 dB(W/(m2·100 MHz)) for all angles of arrival. ( ) WRC-97 In the band 59–64 GHz, airborne radars in the radiolocation service may be operated subject to not causing harmful interference to the inter–satellite service (see No. 43). (WRC-2000)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('559AA', 'The frequency band 66–71 GHz is identified for use by administrations wishing to implement the terrestrial component of International Mobile Telecommunications (IMT). This identification does not preclude the use of this frequency band by any application of the services to which this frequency band is allocated and does not establish priority in the Radio Regulations. Resolution 241 (WRC-19) applies. ( WRC- )');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('559B', 'The use of the frequency band 77.5–78 GHz by the radiolocation service shall be limited to short-range radar for ground-based applications, including automotive radar. The technical characteristics of those radars are provided in the most recent version of Recommendation ITU-R M.2057. The provisions of No. 4.10 do not apply. ( ) WRC-15 In the band 78–79 GHz radars located on space stations may be operated on a primary basis in the Earth exploration–satellite service and in the space research service. In the band 74–76 GHz, stations in the fixed, mobile and broadcasting services shall not cause harmful interference to stations of the fixed–satellite service or stations of the broadcasting–satellite service operating in accordance with the decisions of the appropriate frequency assignment planning conference for the broadcasting–satellite service. ( WRC-2000)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('561A', 'The 81–81.5 GHz band is also allocated to the amateur and amateur–satellite services on a secondary basis.');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('561B', 'In Japan, use of the band 84–86 GHz, by the fixed–satellite service (Earth-to-space) is limited to feeder links in the broadcasting–satellite service using the geostationary- satellite orbit. ( ) WRC-2000 The use of the band 94–94.1 GHz by the Earth exploration–satellite (active) and space research (active) services is limited to spaceborne cloud radars. ( ) WRC-97');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('562A', 'In the bands 94–94.1 GHz and 130–134 GHz, transmissions from space stations of the Earth exploration–satellite service (active) that are directed into the main beam of a radio astronomy antenna have the potential to damage some radio astronomy receivers. Space agencies operating the transmitters and the radio astronomy stations concerned Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('206', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('562B', 'In the frequency bands 105–109.5 GHz, 111.8–114.25 GHz and 217–226 GHz, the use of this allocation is limited to space-based radio astronomy only. ( ) WRC-19');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('562C', 'Use of the band 116–122.25 GHz by the inter–satellite service is limited to satellites in the geostationary-satellite orbit. The single-entry power flux-density produced by a station in the inter–satellite service, for all conditions and for all methods of modulation, at all altitudes from 0 km to 1 000 km above the Earth’s surface and in the vicinity of all geostationary orbital positions occupied by passive sensors, shall not exceed −148 dB(W/(m2·MHz)) for all angles of arrival. (WRC-2000)');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('562D', 'Additional allocation: in Korea (Rep. of), the frequency bands 128–130 GHz, 171–');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('562E', 'The allocation to the Earth exploration–satellite service (active) is limited to the band');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('562H', 'Use of the bands 174.8–182 GHz and 185–190 GHz by the inter–satellite service is limited to satellites in the geostationary-satellite orbit. The single-entry power flux- density produced by a station in the inter–satellite service, for all conditions and for all methods of modulation, at all altitudes from 0 to 1 000 km above the Earth’s surface and in the vicinity of all geostationary orbital positions occupied by passive sensors, shall not exceed −144 dB(W/(m2·MHz)) for all angles of arrival. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('563A', 'In the bands 200–209 GHz, 235–238 GHz, 250–252 GHz and 265–275 GHz, ground- based passive atmospheric sensing is carried out to monitor atmospheric constituents. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('563B', 'The band 237.9–238 GHz is also allocated to the Earth exploration–satellite service (active) and the space research service (active) for spaceborne cloud radars only. ( ) WRC-2000');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('564A', 'For the operation of fixed and land mobile service applications in frequency bands in the range 275–450 GHz: The frequency bands 275–296 GHz, 306–313 GHz, 318–333 GHz and 356–450 GHz are identified for use by administrations for the implementation of land mobile and fixed service applications, where no specific conditions are necessary to protect Earth exploration-satellite service (passive) applications. The frequency bands 296–306 GHz, 313–318 GHz and 333–356 GHz may only be used by fixed and land mobile service applications when specific conditions to ensure the protection of Earth exploration–satellite service (passive) applications are determined in accordance with Resolution 731 (Rev.WRC-19). Australian Radiofrequency Spectrum Plan 2021');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('207', '');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('275', '–286 GHz, 296–306 GHz, 313–356 GHz, 361–365 GHz, 369–392 GHz, 397– GHz, 409–411 GHz, 416–434 GHz, 439–467 GHz, 477–502 GHz, 523– GHz, 538–581 GHz, 611–630 GHz, 634–654 GHz, 657–692 GHz, 713– GHz, 729–733 GHz, 750–754 GHz, 771–776 GHz, 823–846 GHz, 850– GHz, 857–862 GHz, 866–882 GHz, 905–928 GHz, 951–956 GHz, 968– GHz and 985–990 GHz. The use of the range 275–1 000 GHz by the passive services does not preclude use of this range by active services. Administrations wishing to make frequencies in the');
INSERT INTO spectrum_international_footnotes(footnote_ref, footnote_text) VALUES('208', '');
